(window.courseContent = window.courseContent || {})["000012"] = {"files/Физиотерапия и рехабилитация/Материали/1-msg-Тема 1. Галваничен ток.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">ВИДОВЕ ЕЛЕКТРИЧЕСКИ ТОКОВЕ И ГАЛВАНИЗАЦИЯ</h1><h2>ВИДОВЕ ЕЛЕКТРИЧЕСКИ ТОКОВЕ ИЗПОЛЗВАНИ В ЕЛЕКТРОЛЕЧЕНИЕТО</h2><p>Електрическите токове се делят на два основни вида: постоянни (прави) и променливи.</p><h3>ПОСТОЯННИ ТОКОВЕ</h3><p><strong>Постоянни токове</strong> са тези, при които електроните или йоните се движат постъпателно само в една посока. В зависимост от промените в напрежението и силата им, те се класифицират като:</p><ul><li><strong>Галваничен ток:</strong> При него електроните или йоните се движат постъпателно в една постоянна посока и поддържат постоянно напрежение.</li><li><strong>Пулсиращ ток:</strong> Електроните или йоните се движат постъпателно в една постоянна посока, но менят закономерно своето напрежение, без то да спада до нулева стойност.</li><li><strong>Прекъснат ток:</strong> Електроните или йоните се движат постъпателно в една постоянна посока, но напрежението им се мени така, че след достигане на своя максимум спада до нулева стойност, след което следва пауза и нов импулс.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775035280709-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775035280709-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1024px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>ПРОМЕНЛИВИ ТОКОВЕ</h3><p>Променливи са токовете, при които напрежението, силата и посоката се променят с времето. Те могат да имат симетрична или несиметрична графика. При <strong>синусовия ток </strong>графиката е <strong>симетрична</strong>, докато при <strong>фарадичния ток </strong>тя е <strong>асиметрична</strong>.</p><p>Кривата, описваща тока над абсцисната ос, е приета условно за положителна полувълна, а под нея — за отрицателна полувълна. Двете полувълни заедно образуват една вълна. Времето, за което протича една цяла вълна, се нарича период (Т) или трептене. Броят на трептенията в една секунда се определя като честота, чиято мерна единица е 1 херц (Hz), съответстващ на 1 колебание в секунда.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775035461570-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775035461570-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1024px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>КЛАСИФИКАЦИЯ НА ГИЛДЕМАЙСТЕР (GILDEMEISTER)</h2><p>Според своята честота електрическите токове се разделят на три основни групи:</p><ul><li><strong>Нискочестотни токове:</strong> от 0 до 1000 Hz.</li><li><strong>Средночестотни токове:</strong> от 1000 до 100 000 Hz.</li><li><strong>Високочестотни токове:</strong> над 100 000 Hz.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">ГАЛВАНИЧЕН ТОК&nbsp;</h2><h3>ХАРАКТЕРИСТИКА И РАЗПРОСТРАНЕНИЕ</h3><p>Галваничният ток е <strong>постоянен</strong>, <strong>прав </strong>ток с ниско напрежение (30-80 V) и неголяма сила (до 50 mА). Понеже не мени посоката и силата си, неговото графично изображение е <strong>права линия</strong>, <strong>успоредна на абсцисата</strong>.</p><p>Действието му върху организма се определя от неговото проникване в тъканите. В биологичните среди той се разпространява най-добре там, където има малко омично съпротивление — в кръвоносните и лимфните съдове, мускулите и междуклетъчните пространства. Поради значителното омично съпротивление на кожата, голяма част от енергията при галванизация се поглъща от нея. Част от тази енергия се превръща в топлина, а друга част отключва първични електрохимични процеси. Количеството на генерираната топлина е незначително и без практическа стойност поради малката сила на тока.</p><h3>ФИЗИКО-ХИМИЧНИ ПРОЦЕСИ ПРИ ГАЛВАНИЗАЦИЯ</h3><p>При включване на галваничната верига настъпва ориентация на йоните: отрицателните се насочват към анода, а положителните катиони — към катода. Достигайки полярните зони (електродите), те отдават своя пълнеж и се превръщат в електрически неактивни вещества с нови химични качества. Специфичното действие на галваничния ток се състои именно в промяната на съотношението на йонния състав в тъканите. В резултат на електролитната дисоциация се отключват следните физико-химични процеси:</p><h3>Поляризация</h3><p>Върху мембраните и клетъчните обвивки се натрупват противоположно заредени йони от двете им страни. Това създава потенциална разлика и поражда поляризационен ток, който е обратен на приложения. Този ток изчезва часове след апликацията. Счита се, че тези участъци са местата с най-голяма активност на тока (след епидермиса).</p><h3>Йонна асиметрия</h3><p>Представлява изменение на количественото и качественото съотношение на йоните в тъканите вследствие на преразпределението им към катода и анода. Като резултат от натрупването на катиони при катода и аниони при анода, настъпва промяна на кожното pH под електродите:</p><ul><li><strong>Под катода:</strong> образуват се <strong>основи </strong>и се увеличава количеството на <strong>ацетилхолина</strong>.</li><li><strong>Под анода:</strong> образуват се <strong>киселини </strong>и се засилва <strong>холинестеразната активност</strong>.</li></ul><p>При въздействие с анода нервната мембрана се хиперполяризира (външната ѝ страна се натоварва с излишък от положителни йони), което води до потискане на възбуждението — състояние, известно като <strong>анелектротонус</strong>. При дразнене с катода нервната мембрана се деполяризира — <strong>кателектротонус</strong>.</p><h3>ЗОНИ НА ВЪЗДЕЙСТВИЕ ПРИ ГАЛВАНИЗАЦИЯ</h3><p>Под въздействието на галваничния ток в третираните тъкани се оформят три основни зони. </p><ul><li>Първата включва <strong>полярните зони</strong>, разположени непосредствено под електродите, където се наблюдават предимно явления на <strong>електролиза</strong>. </li><li>Втората зона са <strong>периполярните зони</strong>, които се характеризират с проява на <strong>хиперемия</strong>. </li><li>Третата зона обхваща <strong>интерполярните зони</strong>, разположени между електродите, при които е характерно <strong>повишаване на обмяната на веществата</strong>, подобряване на <strong>тъканната трофика </strong>и повишаване на <strong>клетъчния метаболизъм</strong>.</li></ul><h3>ФИЗИОЛОГИЧНИ ЕФЕКТИ</h3><p>Галваничният ток притежава няколко основни физиологични ефекта, които определят неговото терапевтично приложение:</p><ul><li><strong>Ексцитомоторен ефект:</strong> Предизвиква мускулна контракция чрез деполяризация на мускулното влакно или моторния нерв. Този ефект се проявява <strong>само при бърза промяна в силата на тока</strong> — при включване и изключване на веригата, но не и при постоянното му протичане.</li><li><strong>Аналгетичен ефект:</strong> Наблюдава се основно под анода. Продължителното приложение на тока води до понижаване на тактилната и болева чувствителност на кожата.</li><li><strong>Хиперемия и трофичен ефект:</strong> Предизвиква повърхностна хиперемия, която е по-силно изразена под катода, което подобрява храненето на тъканите.</li><li><strong>Термичен ефект:</strong> Поради използването на ток с много малка големина, генерираната топлина е слаба и не е водещ лечебен фактор.</li></ul><h3>АПЛИКАЦИОННА ТЕХНИКА И ПОДГОТОВКА</h3><p>За правилното провеждане на процедурата е необходимо използването на електроди в добро състояние (изработени от цинк, калай или каучук), които трябва да са <strong>идеално плоски </strong>за осигуряване на плътен контакт. Електродите задължително се поставят в <strong>хидрофилни бархетни възглавнички</strong>, които са предварително намокрени и изцедени. Тези възглавнички трябва да са с малко по-голям размер от електродите и да се изпират след всяка употреба за отстраняване на продуктите от електролизата. Проводниците на апарата са цветово означени: <span style=\"color: rgb(255, 0, 0)\"><strong>плюс </strong></span>(<span style=\"color: rgb(255, 0, 0)\"><strong>анод</strong></span>) в <span style=\"color: rgb(255, 0, 0)\"><strong>червено </strong></span>и <strong>минус </strong>(<strong>катод</strong>) в <strong>черно</strong>.</p><p>Преди процедурата кожата на пациента се почиства от мазнини и потна секреция със слаб спиртен разтвор. Областта на апликация се оглежда за екскориации или други афекции, които трябва задължително да бъдат покрити с изолираща материя, за да се предотврати концентрация на тока в тези области и последващо химично изгаряне.</p><h3>ПАРАМЕТРИ НА ПРОЦЕДУРАТА</h3><p>При определяне на рецептурата са важни два основни параметъра:</p><ol><li><strong>Доза:</strong> Препоръчителната плътност на тока не трябва да надвишава 0,1 mA/cm<sup>2</sup>. Интензитетът се покачва постепенно в началото на процедурата, като се <strong>ръководим от усещанията на пациента</strong>. След няколко минути е възможно леко повишаване на силата на тока поради намаляващото съпротивление на кожата.</li><li><strong>Продължителност:</strong> Обикновено една процедура трае между 20 и 30 минути, като са необходими няколко минути в началото, за да може правият ток да преодолее кожната бариера.</li></ol><h3>ПОКАЗАНИЯ И ПРОТИВОПОКАЗАНИЯ</h3><h4>Показания </h4><p>Галванизацията има обширни показания поради своите аналгетични, трофични и противовъзпалителни ефекти.</p><h4>Противопоказания</h4><p>Процедурата обаче е противопоказана при наличие на метал в тъканите, фебрилни състояния, хеморагии, гнойни процеси, бременност, наличие на пейсмейкър или тумори. Анестезията или хипестезията в третираната зона се считат за относителни противопоказания поради риск от изгаряне.</p><h3>НАЧИНИ НА ПРИЛОЖЕНИЕ И МЕТОДИКИ</h3><p>Галваничният ток може да се прилага по три начина: </p><ul><li><strong>Стабилна галванизация</strong> -<strong> </strong><p>електродите са фиксирани върху тялото, токът </p><p>протича непрекъснато.</p></li><li><strong>Ритмична галванизация  </strong>-<strong> </strong><p>електродите са фиксирани върху тялото, токът се </p><p>подава ритмично през определени паузи.</p></li><li><strong>Лабилна галванизация </strong>-<strong> </strong><p>от източника протича непрекъснат ток, но активният </p><p>електрод е подвижен.</p></li></ul><p>Според разположението на електродите се различават <strong>напречна</strong>, <strong>напречно</strong>-<strong>диагонална </strong>или <strong>надлъжна методика</strong>. </p><p>Когато електродите са с различна големина, за <strong>активен електрод</strong> се счита по-малкият, тъй като в него се концентрират силовите линии. Той се поставя върху зоната, изискваща най-силно въздействие, докато по-големият (<strong>индиферентен</strong>) електрод се позиционира на неутрално място.</p><h2>Методики за общо въздействие</h2><h3>Методика на Вермел</h3><p>Тя намира широко приложение при състояния на невроза, прогресивна мускулна дистрофия и рахит. Методиката е особено ефективна и в периода на възстановяване след различни видове интоксикации.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036331473-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036331473-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 183px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Галванична вана</h3><p>Галваничната вана е изключително подходяща при лечение на периферни парализи, дегенеративни ставни заболявания или хронични възпалителни процеси на ставите, като осигурява цялостно и равномерно въздействие върху засегнатите области.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036364912-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036364912-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 262px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h2>Рефлекторни методики</h2><h3>Яка на Щербак</h3><p>Тази специфична методика съчетава местно и мощно рефлекторно въздействие върху организма. Прилага се при състояния на невроза, хипертонична болест, мигрена и язвена болест. В областта на неврологията се използва активно за третиране на остеохондроза и радикулопатии в цервикалния отдел на гръбначния стълб.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036478777-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036478777-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036478777-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 225px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Гащета на Щербак</h3><p>Прилага се при лечение на нощно напикаване (енуреза) при деца, както и при цистити и простатити. Прилага се също при възпалителни процеси на яйчниците и тръбите (аднексити), а при мъжете — в случаи на импотентност.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036485500-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036485500-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 286px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Интраназална галванизация</h3><p>Използва се за целенасочено повлияване на инервацията и подобряване на кръвоснабдяването в областта на бронхите, като достъпът се осъществява чрез лигавицата на носа.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036506102-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036506102-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 340px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Галванизация на млечните жлези</h3><p>Тази методика има за цел да стимулира секреторната функция на жлезите, както и за отдалечени ефекти върху половите органи в малкия таз, като помага при лечение на метрорагии, менорагии и импотентност.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036516610-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036516610-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 283px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h2>Локални методики</h2><h3>Полумаска на Бергоние</h3><p>Тя е основно средство при неврит на n. facialis и n. trigeminus. Намира приложение и при лечение на артропатия на темпоромандибуларната става.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036557010-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036557010-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 308px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Трансцеребрална галванизация по Бургиньон</h3><p>Използва се при комплексното лечение на болест на Паркинсон, състояния след прекарани инсулти, енцефалити и менингити. Ефективна е и при терапията на хронични главоболия от различен произход.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036587161-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036587161-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 359px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Методика за въздействие върху определена става</h3><p>При локално въздействие върху ставите по принцип се използват електроди с еднакви размери, които се разполагат напречно на ставата. За по-прецизно лечение на малките стави на крайниците (китки, глезени, стъпала) е изключително целесъобразно използването на камерни вани.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036618382-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036618382-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 246px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h3>Методика за въздействие върху определен нерв</h3><p>При тази методика електродите се разполагат надлъжно по анатомичното протежение на съответния нерв. Например, за n. ischiadicus съществуват следните варианти на приложение:</p><ul><li>Единият електрод се поставя в поясно-кръстната област (на страната на увреждането), а вторият се позиционира върху проекцията на нерва в седалищната гънка.</li><li>Единият електрод се поставя на предната повърхност на бедрото, а вторият — на задната повърхност.</li><li>Единият електрод се разполага в областта на седалищната гънка, а вторият — в задколянната ямка.</li></ul><p>По аналогичен начин се изграждат схемите за въздействие и върху други нерви като n. femoralis, n. tibialis и n. peroneus.</p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036642184-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775036642184-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 267px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">ЕЛЕКТРОФОРЕЗА</h1><p>Електрофорезата е електролечебен метод, при който в организма се въвеждат лекарствени вещества чрез използването на галваничен ток. За да бъде успешно реализиран този процес, основно изискване е лекарственото вещество да бъде <strong>електролитно дисоциирано</strong>. При преминаването на постоянен ток през електролитен разтвор йоните започват насочено движение — положително заредените йони се насочват към катода, а отрицателно заредените към анода. Основното правило при апликацията е, че <strong>с всеки електрод се въвеждат само еднозначни на поляритета му йони</strong>.</p><h3>ПРОНИКВАНЕ И ДЕПОНИРАНЕ В ОРГАНИЗМА</h3><p>Лекарствените вещества проникват в тялото предимно през каналите на потните и мастните жлези. Първоначално те се отлагат основно в епидермиса и дермата, като достигат максимум до подкожната мастна тъкан. В тези слоеве се формират <strong>локални кожни депа</strong>, в които лекарството се задържа за различен период — от няколко денонощия (например при адреналин) до 15 дни. От тези депа медикаментът постепенно дифундира по лимфен и кръвен път, разнасяйки се в целия организъм. </p><p>Проницаемостта на тъканите е различна, като най-висока е тя при лигавиците. Следват кожата на корема, гърдите, раменния пояс, бедрата, подбедриците, китките и ходилата.</p><h3>ФАКТОРИ, ВЛИЯЕЩИ ВЪРХУ КОЛИЧЕСТВОТО НА ВЪВЕДЕНОТО ВЕЩЕСТВО</h3><p>Ефективността на въвеждането зависи от няколко ключови фактора:</p><ul><li><strong>pH на кожата:</strong> Киселата реакция на кожата намалява проницаемостта за катиони и улеснява проникването на аниони, докато алкалната реакция има обратен ефект.</li><li><strong>Разтворител:</strong> Най-подходящият разтворител за приготвяне на лекарствените разтвори е дестилираната вода.</li><li><strong>Концентрация:</strong> Количеството на въведените йони е правопропорционално на абсолютното съдържание на йони в разтвора, а не на степента на дисоциация.</li><li><strong>Сила на тока и време (Правило на Ипсер):</strong> Количеството вкарано вещество зависи от силата на тока и времето на действие. Важно е да се отбележи, че след 15-ата минута количеството на вкарваното вещество започва да намалява поради натрупването на „паразитни“ йони (водородни на анода и хидроксилни на катода).</li></ul><h3>ПРЕДИМСТВА ПРЕД ТРАДИЦИОННАТА ТЕРАПИЯ</h3><p>Електрофорезата предлага редица предимства в сравнение със стандартния прием на медикаменти:</p><ul><li><strong>Дълготрайно действие:</strong> Формирането на кожно депо осигурява бавно и равномерно усвояване на медикамента в продължение на няколко дни.</li><li><strong>Локално и рефлекторно въздействие:</strong> Лекарството може да се приложи директно в патологичното огнище, осигурявайки висока концентрация там, без да се натоварва целия организъм.</li><li><strong>Чистота на въздействието:</strong> Въвеждат се само активните йони, на които се разчита за терапевтичен ефект, като се избягват съпътстващите съставки на лекарството.</li><li><strong>Потенциран ефект:</strong> Лекарственото вещество действа на фона на физиологичните ефекти на галваничния ток, които засилват неговото действие.</li><li><strong>Защита на ГИТ:</strong> Избягва се преминаването на медикамента през стомашно-чревния тракт, което предотвратява неговото увреждане.</li></ul><h3>АПЛИКАЦИОННА ТЕХНИКА И ПРИМЕРИ</h3><p>Техниката на апликация е аналогична на тази при галванизацията. Разликата е, че върху хидрофилната възглавничка се поставя воден разтвор на медикамента или филтърна хартия, напоена с него. </p><p>Примери за приложение:</p><ul><li><strong>Бромна яка:</strong> Прилага се при неврастения.</li><li><strong>Йодна яка</strong>: Прилага се при неврастения и&nbsp;<p>при дисфункция на щитовидната жлеза.</p></li><li><strong>Новокаин или Лидокаин:</strong> При болкови синдроми.</li><li><strong>Калций (Ca++):</strong> При забавено образуване на калус след фрактури.</li><li><strong>Нивалин:</strong> При отпадна перифернонервна симптоматика.</li></ul><h3>ПОКАЗАНИЯ И ПРОТИВОПОКАЗАНИЯ</h3><p>Показанията за електрофореза произтичат от тези за галванизация, като се добавя фармакологичното действие на избраното лекарство. </p><p>Противопоказанията включват всички ограничения за галванизация (метали в тъканите, пейсмейкър, тумори, бременност, гнойни процеси и др.), като към тях се добавя и индивидуалната непоносимост или алергия към съответното лекарствено вещество.</p><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Физиотерапия и рехабилитация/Материали/2-msg-Тема 2. Нискочестотна импулсна терапия.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">НИСКОЧЕСТОТНА ИМПУЛСНА ТЕРАПИЯ</h1><h2>ОБЩА ХАРАКТЕРИСТИКА И ВИДОВЕ ТОКОВЕ</h2><p>Нискочестотните импулсни токове се характеризират с честота от 1 до 800 Hz и могат да бъдат моно- или биполярни с различна форма на импулса. Монополярните токове променят напрежението си периодично, но запазват постоянна посока. Класически прототип на тези токове е фарадичният ток — биполярен ток с малка продължителност (1 ms), островърха форма и честота между 50 и 100 Hz. При преминаване през тъканите той не предизвиква електролиза, а неговият основен ефект е дразнещото действие върху нервно-мускулния апарат. За разлика от галваничния ток, при който мускулното съкращение става при включване и изключване, при фарадичния ток то се осъществява през цялото време на протичането му.</p><h2>РЕАКЦИИ ПРИ ДРАЗНЕНЕ И ЧЕСТОТНИ ДИАПАЗОНИ</h2><p>Реакциите на мускула зависят пряко от честотата на приложеното дразнене:</p><ul><li><strong>1-10 Hz:</strong> Наблюдават се единични клонични съкращения, като след всяко от тях следва фаза на пълна релаксация.</li><li><strong>10-30 Hz:</strong> Проявяват се клонични съкращения, при които всеки следващ импулс настъпва преди мускулът да се е отпуснал напълно.</li><li><strong>50-100 Hz:</strong> Постига се трайно тетанично съкращение, при което мускулът остава в състояние на тетанус през цялото време на въздействието.</li></ul><p>Съвременната практика използва неофарадични токове, чиито параметри могат да бъдат прецизно регулирани според нуждите на пациента.</p><h2>КЛИНИЧНИ ПАРАМЕТРИ ПРИ ПРИЛАГАНЕ</h2><p>При провеждането на нискочестотна импулсна терапия се подбират специфични параметри, съобразени с индивидуалното състояние на пациента и състоянието на неговия нервно-мускулен апарат:</p><ul><li><strong>Големина (сила) на тока:</strong> Измерва се в милиампери (mА) и се определя спрямо <strong>реобазата </strong>на тъканите. Силата на тока трябва да бъде в оптимални граници. <p>Когато се цели потискащ ефект върху моторна, сетивна и </p><p>вегетативна възбудимост, силата на тока трябва да бъде прагова по </p><p>отношение на кожните рецептори (усет за леко боцкане) и подпрагова </p><p>по отношение на мускулното съкращение.</p></li><li><strong>Форма на тока:</strong> Може да бъде правоъгълна, триъгълна или експоненциална. Изборът зависи от способността за <p><strong>акомодационната способност</strong> на нервномускулния апарат</p>, която представлява \"акт на свеждане на действащия дразнител към нула\". <p>Акомодацията е характерна за миелиновите влакна.</p>  <p>При </p><p>лезия с последваща денервация, нервът загубва способността си да се </p><p>акомодира към бавно покачващи се импулси, т. е. изпада във </p><p>възбуждение, от което следва контракция на паретичния мускул, докато </p><p>близко разположените здрави мускули, при същия интензитет на тока </p><p>остават неактивни. От това следва важен за практиката извод, че </p><p>токовете с експоненциална и триъгълна форма, с голяма </p><p>продължителност и продължителен преден фронт, предизвикват </p><p>избирателно дразнене върху денервираните мускули, като </p><p>същевременно здравите остават неактивирани.</p></li></ul><ul><li><strong>Продължителност на импулса:</strong> Измерва се в милисекунди (ms) и се съобразява с <strong>хронаксията </strong>— времето, необходимо за предизвикване на прагов ефект при сила на тока от две реобази. При здрав човек това време е много кратко, но при увреждания на нерва се удължава значително. При състояния с повишена възбудимост се използват кратки импулси (0,05 до 0,50 ms), докато при отпадна симптоматика продължителността трябва да бъде увеличена.</li><li><strong>Продължителност на паузата:</strong> Този параметър е свързан с <strong>рефрактерната фаза</strong>, която е абсолютно необходима за протичането на химичните възстановителни процеси в мускула след всеки импулс. <p>Ако импулс попадне в </p><p>абсолютната рефрактерна фаза, той не отключва възбуждение. </p>При увреждане на нерва е необходим по-дълъг период за енергетично възстановяване, поради което се използват по-големи паузи между отделните импулси. Обикновено съотношението импулс към пауза варира от 1:2 до 1:6.</li><li><strong>Модулация:</strong> Позволява ритмичното извършване на електростимулациите в серии от импулси, като броят им може да варира от 5 до 30 в минута. Колкото<strong> по-тежка е увредата, толкова по-малък трябва да бъде броят на модулациите</strong>. <p>Когато </p><p>импулсите, включени в една серия не променят амплитудата си се касае за </p><p>групова модулация. Ако в една серия амплитудния пик варира от 0 до </p><p>даден максимум на напрежението и отново до 0 – амплитудна </p><p>модулация.</p></li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775038037019-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775038037019-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 901px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h2>ОСНОВНИ ФИЗИОЛОГИЧНИ ЕФЕКТИ НА НИСКОЧЕСТОТНИТЕ ИМПУЛСНИ ТОКОВЕ</h2><p>Основните физиологични ефекти, на чието лечебно действие се разчита при прилагането на нискочестотни импулсни токове, се изразяват в два основни аспекта: </p><h3>1. СТИМУЛИРАЩ ЕФЕКТ</h3><p>Стимулиращият ефект се проявява чрез няколко ключови механизма върху тъканите и системите на организма:</p><ul><li><strong>Ексцитомоторен ефект:</strong> Предизвиква се върху напречнонабраздената и гладката мускулатура.</li><li><strong>Ревулзивен и трофичен ефект:</strong> Подобрява трофиката на тъканите и улеснява венозния отток.</li><li><strong>Секреторен ефект:</strong> Стимулира секреторната функция на жлезите с вътрешна секреция.</li></ul><h4>Приложение при увреда на периферните нерви</h4><p>При тези състояния електростимулациите подобряват кръво- и лимфообращението на мускулите и тяхната трофика, като същевременно поддържат възбудимостта на дисталния участък на засегнатия нерв и стимулират регенерацията. Прилагат се <strong>импулси с малка честота</strong> /0,25 до 0,75 Hz при тотална денервация и 1-5-10 до 20-30 Hz при частична/, <strong>голяма продължителност</strong> /20-50-100-200ms, а при тотална денервация 300-600ms/, <strong>голяма пауза</strong> /2-3 пъти по-дълга от импулса, а при тотална денервация 4 до 6 пъти/ и <strong>експоненциална форма</strong>. </p><h4>Приложение при хипотрофии и атонии</h4><ul><li><strong>Инактивитетни хипотрофии:</strong> Рецептурата съдържа <strong>правоъгълни импулси с кратка продължителност </strong>(1-10 ms) и <strong>по-голяма честота</strong> (30-50 Hz).</li><li><strong>Атонии на гладката мускулатура:</strong> Електростимулациите се използват широко при постоперационни чревни атонии, атония на пикочния мехур, както и при атония на сфинктери и детрузори при инконтиненция на урината.</li></ul><h4>Специфични приложения и методики</h4><ul><li><strong>Слединсултни състояния:</strong> Извършва се електростимулация на релативно слабите мускули (антагонисти на спастичните) — екстензори на китката и пръстите, четириглав мускул на крака, фибуларна група и екстензори на пръстите. <p>Разчита се на </p><p>реципрочния механизъм, чрез който, стимулирайки слабите мускули на </p><p>паретичната страна, ще постигнем релаксация на спастичните им антагонисти.</p></li><li><strong>Сетивна симптоматика:</strong> Дразнещият ефект се използва при отпадна повърхностна и дълбока сетивност.</li><li><strong>Тъканни изменения:</strong> Поради ревулзивния и разнасящ ефект, токовете са показани при миогелози, посттравматични едеми, дегенеративни изменения в периферните стави и гръбначния стълб.</li><li><strong>Съдови заболявания:</strong> При облитериращи заболявания на периферните съдове стимулацията се прилага надлъжно на мускула в съответната област.</li></ul><h3>2. ИНХИБИРАЩ ЕФЕКТ</h3><p>Вторият основен ефект на нискочестотните импулсни токове е инхибиращият. Той намира най-голямо приложение в следните направления:</p><h4>По отношение на болката (Аналгезиращ ефект)</h4><p>Този ефект представлява процес на потискане, който се получава при ритмични въздействия <strong>с малка продължителност и честота</strong> в диапазона 80—100—250 Hz. Феноменът намира своята теоретична обосновка в <strong>Gate-теорията</strong> на Melzack и Wall (1965 г.):</p><ul><li><strong><span style=\"color: rgb(88, 129, 87)\">Специфични влакна:</span></strong> Болковото усещане се пренася от тънки <strong>миелинизирани влакна </strong>(<strong>А-делта за остра болка</strong>) и <strong>немиелинизирани влакна </strong>(<strong>C за термална, механична изгаряща болка</strong>).</li><li><strong><span style=\"color: rgb(88, 129, 87)\">Потискащи влакна:</span></strong> <strong>Дебелите миелинизирани влакна </strong>(<strong>А-бета</strong>) са в състояние да потиснат предаването на болковия импулс.</li><li><span style=\"color: rgb(88, 129, 87)\"><strong>Substantia gelatinosa:</strong> </span>Двете групи влакна се събират в тази част на задните рога на гръбначния мозък, която контролира възприятието и потискането на болката. Болка се възприема само когато болковият импулс е по-силен от болкоуспокояващия.</li></ul><p>Практическото използване на този механизъм се осъществява чрез <strong>TENS</strong> (транскутанна електрична нервна стимулация). Тя се прилага директно в огнището на болката, в съответния дерматом или по хода на нерва, като големината на тока се контролира в диапазона 5—15 mА.</p><h4>По отношение на мускулния тонус и съдовата стена</h4><ul><li><strong>Тонолитичен ефект:</strong> Освен чрез реципрочна инервация, тонолиза се постига при директно въздействие върху спастичните мускули с честота от 100 до 250 Hz.</li><li><strong>Съдоразширяващ ефект:</strong> Нискочестотните токове оказват вазодилатиращ ефект с последващ хипотензивен такъв. Прилагат се токове с правоъгълна форма (0,5-1 ms, 100 Hz) в синукаротидната област (яка на Щербак) или в областта на бъбреците.</li></ul><h4>Противопоказания</h4><p>Това са пейсмейкьр, остри възпалителни процеси, инфекциозни заболявания и фебрилитет.</p><br><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Физиотерапия и рехабилитация/Материали/3-msg-Тема 3. Диадинамични токове.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">ДИАДИНАМИЧНИ ТОКОВЕ</h1><h2>Определение и физична характеристика</h2><p>Диадинамичните токове са въведени в медицинската практика от френския стоматолог Пиер Бернар. Те представляват монополярни импулсни токове с полусинусоидална форма на импулса. Получават се чрез еднопътно или двупътно изправяне на синусоидалния променлив ток от електрическата мрежа.</p><p>В клиничната практика тези токове много често се наслояват върху галванична основа. Галваничната компонента служи като база, която подобрява електропроводимостта на тъканите и потенцира ефекта на импулсната съставка. В зависимост от конструкцията на апаратурата, галваничната компонента може да бъде фиксирана или да се регулира в степени, като чистата пулсираща компонента се приема за 100%, а нулевата стойност съответства на чист галваничен ток.</p><h2>Видове модулации на диадинамичните токове</h2><p>В съвременната диадинамотерапия се използват няколко основни модулации, които се различават по честота и ритъм на подаване:</p><ul><li><strong>Двуфазно фиксиран ток (DF):</strong> Получава се при двупътно изправяне на синусоидалния ток, в резултат на което се генерира непрекъснат монополярен ток с честота 100 Hz.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775038851317-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775038851317-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 410px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>Монофазно фиксиран ток (MF):</strong> Представлява еднопътно изправен ток с честота 50 Hz, при който продължителността на импулса е 10 ms, последвана от пауза със същата продължителност (10 ms).</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775038909046-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775038909046-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 410px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>Къси серии (CP):</strong> Тази модулация представлява равномерно и ритмично редуване на монофазно фиксиран (MF) и двуфазно фиксиран (DF) ток, като всеки от тях протича с еднаква продължителност от 1 секунда.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775038986056-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775038986056-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 512px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>Дълги серии (LP):</strong> Състои се от последователно редуване на MF и DF ток, но в съотношение, което е в полза на двуфазния ток. Примерно съотношение е 6 секунди за MF и 10 секунди за DF.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775039164506-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775039164506-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 512px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>Ритъм синкоп (RS):</strong> Представлява редуване на монофазно фиксиран ток (MF) за 1 секунда, последван от пауза с продължителност 1 секунда.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775039434274-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775039434274-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 512px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><ul><li><strong>Монофазно модулиран ток (MM):</strong> Включва амплитудно модулиран монофазно фиксиран ток, който протича в продължение на 7 секунди, след което следва пълна пауза от още 7 секунди.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775039830608-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775039830608-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 701px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h2>Терапевтични ефекти и приложение на модулациите</h2><p>Всяка от модулациите на Бернар притежава специфично физиологично действие, което определя избора ѝ при различните патологични състояния:</p><ul><li><p><strong>Монофазно фиксиран ток (MF):</strong> Характеризира се с първичен <strong>ексцитомоторен ефект </strong>(предизвиква мускулна контракция с малка сила) и последващ, по-късно настъпващ потискащ ефект. Привикването при него настъпва по-късно в сравнение с DF. </p><p>Прилага се при болкови синдроми, обикновено след двуфазно</p><p>фиксираната модулация. Предимството му е, че съчетава <strong>обезболяващия с </strong></p><p><strong>трофичен ефект</strong>;</p></li><li><strong>Двуфазно фиксиран ток (DF):</strong> Притежава изразен <strong>симпатиколитичен ефект </strong>и <strong>аналгетично действие</strong>, базирано на повишаване на сетивния праг. При по-висок интензитет на тока може да се наблюдава и <strong>ексцитомоторен ефект</strong>. Използва се предимно при болкови синдроми, причинени от вазоконстрикция, свързана с вегетативната нервна система. <i><p>Важно е да се отбележи, че при DF привикването настъпва бързо — само 4-5 секунди след началото на процедурата. </p><p>За да се избегне това се използва редуване на двата </p><p>основни тока DF и MF в определени интервали от време, като така се </p><p>получават останалите модалности;</p></i></li><li><strong>Къси серии (CP):</strong> Комбинира <strong>обезболяващото </strong>действие с ефект на <strong>разнасяне на отоци и хематоми</strong>. Подпомага релаксацията на напречнонабраздената мускулатура и е метод на избор при болки от травматичен произход.</li><li><strong>Дълги серии (LP):</strong> Осигурява <strong>силен и дълготраен аналгетичен ефект</strong>. Често се прилага в комбинация с къси серии (CP) за успешно лечение на невралгии.</li><li><strong>Ритъм синкоп (RS):</strong> Използва се за <strong>електростимулация на гладката и напречнонабраздената мускулатура</strong> при <strong>запазена инервация</strong>.</li></ul><h2>Показания за лечение с ДДТ</h2><p>Диадинамичните токове имат широк спектър от клинични индикации:</p><ul><li><strong>Заболявания на периферната нервна система:</strong> Неврити, невралгии, радикулити, полиневропатии, дискова херния, парализи и мускулни атрофии.</li><li><strong>Заболявания на вегетативната нервна система и съдови нарушения:</strong> Мигрена, синдром на Рейно, акроцианоза, болест на Бюргер и атонични рани.</li><li><strong>Заболявания на опорно-двигателния апарат:</strong> Артрозна болест, миалгии, миозити, тендовагинити, бурсити, състояния след фрактури и дисторзии.</li><li><strong>Бронхиална астма</strong> - чрез паравертебрално въздействие с адреналин в цервико-торакалната област</li><li><p><strong>Enuresis nocturna</strong> - </p><p>с DF и RS, води до повишаване на снижения тонус </p><p>на детрузора и сфинктера на пикочния мехур.</p><br></li><li><p><strong>Намаляване на артериалното налягане</strong> при въздействие върху шийните симпатикусови ганглии.</p></li></ul><h2>Класически методики и електрофореза</h2><p>Една от най-използваните схеми за обезболяване в клиничната практика е класическата формула на Бернар. Тя включва последователно прилагане на:</p><ol><li><strong>DF (Двуфазно фиксиран ток)</strong> — 1 минута;</li><li><strong>CP (Къси серии)</strong> — от 3 до 5 минути;</li><li><strong>LP (Дълги серии)</strong> — от 5 до 7 минути.</li></ol><p>Освен като самостоятелен терапевтичен метод, диадинамичните токове се използват и за електрофореза, процес известен като <strong>диадинамофореза</strong>.</p><h2>Противопоказания</h2><p>Прилагането на ДДТ е абсолютно противопоказано при следните състояния:</p><ul><li>Туморни процеси и наличие на гнойни огнища.</li><li>Остър тромбофлебит, хеморагии и активни инфекциозни заболявания.</li><li>Наличие на метални импланти в зоната на третиране и наличие на пейсмейкър.</li><li>Бременност и фебрилни състояния.</li><li>Силно изразени мускулни контрактури.</li></ul><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Физиотерапия и рехабилитация/Материали/4-msg-Тема 4. Интерферентни токове.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">ИНТЕРФЕРЕНТНИ ТОКОВЕ</h1><h2>Произход и физичен принцип</h2><p>Интерферентните токове (ИТ) са открити и предложени за използване в лечебната практика от австрийския учен Nemec през 1949 г. При тази методика върху третирания участък се въздейства едновременно с два средночестотни променливи тока с постоянна амплитуда, които се въвеждат чрез два чифта електроди. Електродите се разполагат перпендикулярно един на друг, така че силовите им линии да се кръстосват. Честотата на първия токов кръг е фиксирана на <strong>4000 Hz</strong>, докато при втория тя се променя автоматично в диапазона от <strong>4001 до 4100 Hz</strong>.</p><p>Когато двата средночестотни тока се кръстосат в дълбочината на тъканите, настъпва феноменът <strong>интерференция</strong>. В резултат на това се поражда ендогенно образуван трети ток с честота, равна на разликата между честотите на двата изходни кръга (от <strong>1 до 100 Hz</strong>), на чието лечебно действие се разчита в терапията.</p><h2>Усещания и апаратура</h2><p>Усещанията при въздействие с ИТ се описват като дълбоки вибрации с променлив характер, зависещ от честотата. Най-отчетливо това се усеща в мускулатурата под и в близост до електродите, където се създава най-голяма плътност на тока. Първоначалното равномерно разпределение на тока постепенно се затруднява от съпротивлението на различните тъканни структури, поради което <strong>интерференция настъпва както в дълбоките, така и в повърхностните тъкани</strong>.</p><p>Апаратите за интерферентна терапия разполагат с два чифта електроди, като всеки токов кръг е цветово означен. Съвременните устройства са снабдени с еластични „електроди камбанки“ от еластична материя, които позволяват реализирането на вакуумно въздействие върху кожата. Към някои апарати се прилагат и електроди с форма на ръкавица, които се поставят върху гумени ръкавици – <strong>интерференц-кинезия</strong>.<br>Терапевтът може да избира между постоянна честота (напр. 100 Hz) или автоматично променяща се честота в различни варианти (0—100 Hz, 90—100 Hz, 50—100 Hz).<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775040411850-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775040411850-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1058px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><h2>Физиологични отговори според честотите</h2><p>Чрез избор на честоти получаваме различни физиологични отговори, като най-общо честотите от 10 до 50 Hz притежават ексцитомоторен ефект, а от 50 до 100 Hz седативен, като вътре в посочените граници се наблюдават следните нюанси:</p><ul><li><strong>1 до 15 Hz:</strong> Предизвикват бавни клонични контракции (силен <strong>ексцитомоторен ефект</strong>).</li><li><strong>15 до 80 Hz:</strong> Мускулните контракции са бързи с характер на тетанус; този диапазон има и силен <strong>вазомоторен ефект</strong>.</li><li><strong>80 до 100 Hz:</strong> Предизвикват бързи вибрации с картина на постоянен тетанус и имат подчертан <strong>аналгетичен </strong>и <strong>хиперемиращ ефект</strong>.</li><li><strong>100 Hz (постоянна честота):</strong> Проявяват <strong>симпатиколитичен ефект </strong>и премахват съдовите спазми.</li><li><strong>90 до 100 Hz:</strong> Оказват <strong>седативен </strong>и <strong>спазмолитичен ефект</strong>, като същевременно се избягва привикването на тъканите към дразнителя. Тази честота <u>стимулира и остеогенезата</u>.</li><li><strong>1 до 100 Hz:</strong> Съчетават <strong>динамогенно</strong>, <strong>трофично</strong>, <strong>спазмолитично </strong>и <strong>аналгезиращо действие</strong>, <u>без да предизвикват мускулна умора</u>.&nbsp;</li><li><strong>0 до 100 Hz:</strong> Стимулира разнасянето на калциевите отлагания.</li></ul><h2>Терапевтични ефекти и биологично действие</h2><p>Основният симпатиколитичен ефект на ИТ води до изразена вазодилатация в периферната съдова мрежа и активна хиперемия, съпроводена с отделяне на биологично активни вещества като ацетилхолин и хистамин. <strong>Подобрената кръвна циркулация</strong> ускорява тъканния метаболизъм и резорбтивните процеси, което създава условия за <strong>противооточен</strong>, <strong>противовъзпалителен </strong>и <strong>аналгетичен ефект</strong>.</p><p>Интерферентните токове променят pH на средата към алкална и стимулират продукцията на ацетилхолин. Приложението им в ритмична честота от 1 до 100 Hz стимулира регенерацията на увредените периферни нерви и подобрява функционалното състояние на нервно-мускулния апарат. Освен това ИТ <strong>стимулират остеогенезата </strong>и <strong>ускоряват калусообразуването </strong>чрез засилване на тъканния метаболизъм.</p><h2>Методика на приложение</h2><p>ИТ могат да се прилагат по няколко начина, като се допуска тяхното комбиниране:</p><ul><li><strong>Локално:</strong> Директно върху засегнатата зона.</li><li><strong>Сегментарно:</strong> В областите на симпатикусовите възли (паравертебрално) и в зоните на Захарин—Хед.</li></ul><p>Големината на тока се дозира според субективната поносимост на пациента, като целта е достигане до усещане за неболезнени мускулни контракции.</p><h2>Показания и противопоказания</h2><p><strong>Показания:</strong></p><ul><li>Хронични възпалителни и дегенеративни заболявания на опорно-двигателния апарат.</li><li>Неврити, невралгии и радикулити.</li><li>Посттравматични състояния: контузии, навяхвания, контрактури, състояния след луксации и фрактури.</li><li>Хронични възпалителни заболявания на женските полови органи и хроничен простатит.</li><li>Атрофия на Zudeck, болест на Бюргер и болест на Рейно.</li><li>Професионални заболявания, например вибрационна болест.</li></ul><p><strong>Противопоказания:</strong></p><ul><li>Остри възпалителни заболявания и фебрилитет.</li><li>Тромбофлебит и напреднала атеросклероза.</li><li>Туберкулоза и туморни процеси.</li><li><strong>Болест на Паркинсон</strong>.</li><li>Бременност.</li><li><strong>Деца на възраст под две години</strong>.&nbsp;</li><li>Пейсмейкър.</li></ul><blockquote>Метални импланти не влизат в противопоказания.</blockquote><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Физиотерапия и рехабилитация/Материали/5-msg-Тема 5. Магнитотерапия. Ултразвук и Фонофореза..html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">МАГНИТОТЕРАПИЯ</h1><h2>Обща характеристика и физични основи</h2><p>Магнитните полета са естествена част от човешкия организъм, а самият човек е постоянно потопен в магнитното поле на Земята. Геомагнитното поле изпълнява защитна функция, като не пропуска вредните йонизиращи лъчения и космическите частици. </p><p>Източниците на магнитно поле, използвани в практиката, биват два вида:</p><ul><li><strong>Естествени:</strong> Желязна руда.</li><li><strong>Изкуствени (индуктори):</strong> Създават се на принципа, че електричният ток генерира магнитно поле около себе си. Биват индуктори-соленоиди и индуктори-електромагнити.</li></ul><p>Магнитното поле се характеризира чрез два основни параметъра:</p><ol><li><strong>Напрегнатост:</strong> Измерва се в<strong> А/m</strong> (по системата SI) или в <strong>Ое </strong>(Оерщеда, по системата CGS), като 1 Ое = 79,58 А/m.</li><li><strong>Магнитна индукция:</strong> Характеризира полето в тъканите и се измерва в <strong>Т</strong> (Тeсла по системата SI) или в <strong>Gs</strong> (Гаус по системата CGS), като 1 мТ = 10 Gs.</li></ol><h2>Видове магнитни полета и полярност</h2><ul><li><strong>Постоянни:</strong> Непроменящи се във времето и пространството.</li><li><strong>Променливи:</strong> </li><ul><li><strong>Синусоидални </strong>- <p>чиято характеристика е синусоидална функция на </p><p>времето.</p></li><li><strong>Пулсиращи </strong>- <p>периодично изменящо се МП, без промяна в </p><p>направлението.</p></li><li><strong>Импулсни </strong>- <p>с импулсен характер.</p></li></ul></ul><p>Във физиотерапията се използват: основно постоянното МП и променливото синусоидално МП, прилагани в <strong>непрекъснат </strong>или <strong>импулсен режим</strong>. </p><p>Важно значение има полярността на магнита:</p><ul><li><strong>Северен полюс (отрицателна полярност):</strong> Действа разпръскващо на енергията, има охлаждащ и успокояващ ефект върху организма.</li><li><strong>Южен полюс (положителна полярност):</strong> Концентрира енергията, има затоплящо и възбуждащо действие.</li></ul><h2>Механизъм на действие</h2><p>Макар механизмът на въздействие на магнитотерапията да не е напълно изяснен, съществуват над 20 хипотези. Сред най-вероятните са:</p><ul><li><strong>Изменения в свойствата на водната молекула в тялото и преминаването на водата от поляризирано в неполяризирано състояние</strong>.</li><li><strong>Активиране на биологичното окисление</strong> в митохондриите, което влияе върху скоростта на синтеза на АТФ.</li><li><strong>Забавяне на биохимичните реакции</strong>, което повлиява процесите на остаряване на клетките.</li><li><strong>Прилагане на теорията на Селие за адаптацията</strong>.</li><li><p><strong>Влияние върху транспорта на заредените частици</strong> – йони и </p><p>електрони.</p><br></li></ul><h2>Въздействие върху човешкия организъм</h2><p>Магнитотерапията оказва многостранно влияние върху различните системи в тялото, като трите най-важни ефекта са <strong><u>!</u></strong><strong><u>обезболяващ, противовъзпалителен и трофичен!</u></strong>.</p><ul><li>Най-значителното действие е <strong>успокояването на болката</strong>. Особено при болки вследствие на травми. Изключително добър ефект има при повлияване на болевата и възпалителна компонента при различни видове артрити, артрозна болест, радикулерни, дискогенни и други синдроми.</li><li>Специфично действие върху хемостазата. При слабо магнитно поле <strong>хипокоагулационния ефект </strong>може да бъде променен в посока на <strong>хиперкоагулация</strong>.</li><li><strong>Противовъзпалително действие</strong>. Магнитното поле предизвиква активация на глюко- и минералкортикоидната функция на надбъбрецитеи щитовидната жлеза. Повишава се имунологичната реактивност и микроциркулацията. Повишава се общата резистентност на организма и намалява заболеваемостта от различни вирусни и бактериални заболявания.</li><li>Върху НС <strong>засилва задръжните процеси в ЦНС</strong>, като най-чувствителни към това са хипоталамусът и кората. Магнитното поле стимулира или потиска освобождаването на невромедиаторните субстанции и по този начин повлиява и болевата сетивност. Освен това магнитното поле стимулира парасимпатикуса, което води до повишено отделяне на хистамин.</li><li><strong>Противооточно, обезболяващо и стимулиращо регенерацията на тъканите</strong> – особено при болни с <strong>шийна остеохондроза </strong>и притискане на нервни коренчета. Повлиява изключително добре клиниката при диабетни полиневрити, радикулити, фантомни болки и др.</li><li>Върху ставите <strong>подобрява смазващата функция на синовиалната течност</strong>, забавя остаряването, подпомага бързото зарастване на фрактурите.</li><li>Върху ССС води до снижаване на бета-адренергичните реакции и депонирането на катехоламините в миокарда. Магнитното поле води до <strong>меко хипотензивно действие</strong>.</li><li><strong>Подобрява </strong>съществено <strong>артериалното</strong>, <strong>венозното и капилярното кръвообръщение</strong>, повишава фибринолитичната активност и съдържанието на хепарина при Бюргер и атеросклеротични облитерации на крайниците.</li><li><strong>Подобрява метаболизма </strong>и особено обмяната на уреята, холестерола и въглехидратите, лекува безсънието и се използва също при различните видове затлъстявания.</li><li>Действа ефективно върху различни <strong>кожни заболявания </strong>като псориазис, екземи, алергии и др.</li><li>Отслабеното магнитно поле води до появата на <strong>остеопороза</strong>, като загубата на калций при същото заболяване може да бъде спряно чрез въздействие с магнитoтерапия.</li></ul><h2>Параметри на процедурата и клинично приложение</h2><p>Ефективността на лечението зависи от дозировката и режима на работа:</p><ul><li><strong>Продължителност:</strong> Курсът обикновено включва 10–15 до 30 процедури с времетраене от 6 до 30 минути.</li><li><strong>Малки мощности (4–40 Ое):</strong> Имат стимулиращо действие и се използват при остри възпалителни процеси.</li><li><strong>Високи стойности (50–500 Ое):</strong> Действат потискащо и са подходящи за хронични възпаления.</li><li><strong>Режим:</strong> Импулсният режим засилва действието на магнитотерапията.</li></ul><p>Магнитотерапията подобрява метаболизма (обмяна на уреята, холестерола и въглехидратите) и се използва при затлъстяване и безсъние.</p><h2>Противопоказания и странични ефекти</h2><p>Прилагането на магнитотерапия изисква съобразяване със следните ограничения:</p><p><strong>Абсолютни противопоказания:</strong></p><ul><li>Наличие на пейсмейкър.</li><li>Бременност.</li><li>Активна туберкулоза.</li><li>Склонност към кръвотечения.</li><li>Тежка исхемична болест на сърцето (ИБС).</li><li>Хипотония.</li></ul><p><strong>Относителни противопоказания:</strong></p><ul><li>Тежки психични заболявания.</li><li>Тежки онкологични заболявания в терминален стадий.</li><li>Период на химиотерапия (поради възможнo инхибиране на действието на цитостатиците).</li></ul><p><strong>Странични действия:</strong> Появяват се много рядко и могат да включват признаци на нервно разстройство, леко повишаване на кръвното налягане или сърцебиене.</p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">УЛТРАЗВУК</h1><h2>Физична характеристика и разпространение</h2><p>Ултразвукът представлява механични, колебателни и вълнообразно разпространяващи се движения на частиците в еластична материална среда като вода или въздух. Тези вълни имат честота над 20 kHz, като за нуждите на ултразвуковата терапия се използва енергията на частици с честота от 800 до 3000 kHz. При своето разпространение в нееднородна среда ултразвуковите вълни могат да се пречупват, отразяват или поглъщат, като една част от тях преминава праволинейно в следващата среда.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Отражение и контактни среди</h2><p>Когато акустичното съпротивление на две среди е съвсем различно, падащите вълни се отразяват почти напълно от границата между тях. Такъв е случаят на границата между тъканите на организма и въздуха, където отражението достига 99,7%. Поради тази причина по време на процедура е критично важно да се осигури <strong>!безвъздушен контакт! </strong>на ултразвуковата глава с третирания участък, като за целта се използват контактни среди (вазелин, течен парафин, глицерин или вода). Тъй като коефициентът на отразяване нараства с увеличаване на ъгъла на падане, <strong>!озвучителят задължително се поставя перпендикулярно!</strong> на кожата.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Интерференция и стоящи вълни</h2><p>След отразяване на ултразвука от препятствие (друга среда) може да настъпи наслагване или интерференция на вълните. Това явление се наблюдава основно в тъканите в близост до озвучителя, когато той е в неподвижно положение (стабилен метод). В такива случаи е възможно прегряване на тъканите, което налага намаляване на интензитета на ултразвука.<i> </i></p><p>При перпендикулярно падане върху гранична повърхност и пълно отразяване в обратна посока се образуват <strong>стоящи вълни</strong>. В резултат на триенето при възникването на тези вълни в организма се генерира значителна топлина.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Абсорбция и проникване в тъканите</h2><p>Дълбочината на проникване на ултразвука зависи пряко от честотата на колебанията — колкото по-висока е тя, толкова по-малко прониква вълната. Генераторите с честота <strong>800 </strong>kHz проникват на дълбочина <strong>7-12 cm</strong> и се използват във физиотерапията, докато тези с честота 1500 kHz достигат само 1-2 cm и са предназначени за дерматологията. </p><p>Поглъщането в човешките тъкани е неравномерно: то е най-силно в нервите, мускулите и костите, по-слабо във вътрешните органи и най-слабо в подкожната мазнина. Най-голямо количество енергия се поглъща с образуване на топлина на границите между различните тъкани, като например кожа-подкожна мазнина, фасция-мускул, надкостница-кост или кости-мускули. При наличие на оток в тъканите коефициентът на поглъщане намалява.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Кавитация и биологични процеси</h2><p>Преминаването на ултразвукова вълна през течност води до нейното обезгазяване и отделяне на малки мехурчета на повърхността. Ако вълната премине през вече обезгазена течност, в нея се появяват кухини, наречени <strong>кавитационни мехурчета</strong>. Това явление, известно като псевдокавитация, се наблюдава и в човешките тъкани. Кавитационните мехурчета действат като много активни енергийни центрове, в които протичат бързи биологични, физични и химични процеси.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Генериране на ултразвук и апаратура</h2><p>Във физиотерапията най-често се използват <strong>генератори, работещи на принципа на обратния пиезоелектричен ефект</strong>. Той се постига чрез подлагане на <strong>кварцов кристал </strong>на ритмична деформация в поле с висока честота, при което електричната енергия се превръща в механични трептения. </p><p>Ултразвуковият апарат се състои от<strong> генератор за високочестотен то</strong><strong>к </strong>и <strong>озвучител</strong>. Самият озвучител включва дръжка и метална глава, в която са разположени кварцовата пластинка и вибрираща мембрана (с големина от 1 до 8 cm<sup>2</sup>). Кристалът трепти в резонанс с генератора и излъчва вълни, които се насочват към лекувания участък чрез металната мембрана. </p><p>!!!Приложени в ниски терапевтични дози, тези вълни имат благоприятни ефекти, но при висок интензитет могат да имат разрушително действие върху тъканите.!!!</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>МНОГОСТРАНЕН ЕФЕКТ НА УЛТРАЗВУКА ВЪРХУ ОРГАНИЗМА</h2><p>Ултразвукът (УЗ) притежава комплексно и многопосочно въздействие върху човешкия организъм, което се проявява чрез специфични физични и биологични механизми.</p><h3>1. МЕХАНИЧНО ДЕЙСТВИЕ</h3><p>Под механичното въздействие на ултразвуковите вълни се пораждат вихрови движения на цитоплазмата в клетките, което представлява своеобразен <strong>микромасаж </strong>на тъканите, който активира дифузията през клетъчната мембрана и засилва междуклетъчната обмяна на веществата. В резултат на механичните сили в биологичните тъкани се формира явлението <strong>псевдокавитация</strong>.</p><p>Особено значение има !!<strong>тиксотропното действие!!! </strong>на УЗ, което се изразява в обратима промяна на състоянието на тъканите от гел в зол и подмладяване на вътреклетъчната структура. Този механизъм е в основата на:</p><ul><li>Фибринолитичното действие и размекването на цикатрикси.</li><li>Натрупването на гликоген и мукополизахариди в клетките.</li><li>Активирането на синтеза на хиалуронова и хондроитин-сярна киселина.</li><li>Хондропротективния ефект върху ставите.</li></ul><h3>2. ТЕРМИЧЕН ЕФЕКТ</h3><p>Топлинното въздействие се дължи главно на поглъщането на механичната ултразвукова енергия от тъканите и нейното превръщане в топлина. При използване на ниски терапевтични дозировки и импулсно приложение, топлинната и механичната компонента действат синергично за:</p><ul><li>Засилване на пермеабилитета на клетъчните мембрани и обмяната на веществата.</li><li>Повишаване на нервната проводимост и мембранните потенциали.</li><li>Намаляване на спазмите на набраздената и гладка мускулатура.</li></ul><h3>3. ФИЗИКО-ХИМИЧЕН ЕФЕКТ</h3><p>В зоната на ултразвуково въздействие настъпват редица вторични физико-химични реакции, които имат подчертан саногенезен (оздравителен) ефект.</p><h4>Антиалергично и противовъзпалително действие</h4><p>Антиалергичният ефект се постига чрез свързване и неутрализиране на излишното количество хистамин в кръвните белтъци и активиране на глюкокортикоидната функция на надбъбреците. </p><p>При заболявания като <strong>болест на Бехтерев и ревматоиден артрит</strong>, УЗ намалява активността на възпалителния процес, нормализира съдържанието на глобулиновите фракции и намалява нивата на глюкозамини и сиалова киселина в кръвта.</p><h4>Въздействие върху имунната система</h4><p>При <strong>лечение на тонзилити </strong>се наблюдава засилено синтезиране на IgA, който осигурява защитен ефект върху лигавицата на сливиците и горните дихателни пътища, както и повишена активност на лимфоцитите към патогени.</p><h4>Въздействие върхну нервната система</h4><p>Въздействието върху нервната система зависи строго от приложената доза:</p><ul><li><strong>Малки дози </strong>(0,2 W/cm<sup>2</sup>) в импулсен режим стимулират нервните структури и подобряват отпадната симптоматика при паралитичен ишиас.</li><li><strong>По-големи дози </strong>(0,5—0,7 W/cm<sup>2</sup>) могат да доведат до задълбочаване на намалената моторна и кожносетивна възбудимост.</li></ul><h4>Рефлекторно и регенеративно действие</h4><p>Приложението в зоните на <strong>Захарин-Хед</strong> има нервно-рефлекторно въздействие, което нормализира състоянието на съдовата гладка мускулатура и вътрешните органи. </p><p>УЗ оказва нормализиращ ефект върху симпатико-адреналната система, като приложението върху симпатикови ганглии (0,2 W/cm<sup>2</sup>) действа нормотонично при периферносъдови разстройства. </p><p>Ултразвукът подобрява и процеса на калусообразуване при фрактури.</p><h4>Приложение в офталмологията</h4><p>В очната практика ултразвуковата терапия стимулира регенерацията, успокоява възпалителните процеси, намалява отока на стромата, ускорява разнасянето на фибрина и намалява съединително-тъканните ръбци.</p><h3>4. БАКТЕРИЦИДЕН ЕФЕКТ</h3><p>Наблюдава се върху коли бактерии при висок интензитет (3 W/cm<sup>2</sup>) и честота 1 MHz. Това действие се обяснява с разтварянето на бактериите, разпадането на определени белтъчни групи и ефекта на кавитация, предизвикан от вълните. Този ефект намира приложение предимно в дерматологията при лечение на кожни възпалителни процеси.</p><h3>ОБОБЩЕНО ТЕРАПЕВТИЧНО ДЕЙСТВИЕ</h3><p>Въз основа на многостранните си ефекти, терапевтичното действие на ултразвука се обобщава като:</p><ul><li>Фибринолитично и противовъзпалително.</li><li>Обезболяващо и антиалергично.</li><li>Нормализиращо съдовия тонус и подобряващо обмяната на веществата.</li><li>Стимулиращо регенерацията на тъканите и калусообразуването.</li><li>Хиперемизиращо и бактерицидно.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>МЕТОДИ НА ПРИЛОЖЕНИЕ</h2><p>В клиничната практика приложението на ултразвук се разделя на два основни метода в зависимост от начина на контакт с тъканите:</p><ul><li><strong>Директен метод:</strong> При него озвучителят влиза в пряк контакт с кожата на пациента чрез контактна среда. Той се подразделя на:</li><ul><li> <strong>Стабилен метод</strong>, при който озвучителят се прикрепва неподвижно към лекуваната част с помощта на специално приспособление,</li><li><strong>Лабилен метод</strong>, при който областта се масажира с плавни кръгови или линейни движения.</li></ul><li><strong>Индиректен метод:</strong> Извършва се чрез използването на дегазирана (преварена или дестилирана) вода като проводник. Този метод включва:</li><ul><li><strong>Субаквален метод</strong>, при който крайникът се поставя във ваничка с вода, а озвучителят се движи или фиксира от терапевта</li><li><strong>Опосредствен метод</strong>, при който озвучаването преминава през гумен мехур с вода или специални наконечници пълни с вода, фиксирани към главата на апарата.</li></ul></ul><h2>ИНТЕНЗИТЕТ И ДОЗИРОВКА</h2><p>Интензитетът на ултразвука представлява количеството енергия, преминаващо през площ от 1 cm<sup>2</sup> на мембраната, и се измерва в W/cm<sup>2</sup>. Дозировките се класифицират в три нива:</p><ul><li><strong>Ниски дози:</strong> 0,01—0,4 W/cm<sup>2</sup>.</li><li><strong>Средни дози:</strong> 0,5—0,7 W/cm<sup>2</sup>.</li><li><strong>Високи дози:</strong> 0,8—1,2 W/cm<sup>2</sup>.</li></ul><p>При лабилния метод се използват стойности от 0,1 до 0,8 W/cm<sup>2</sup>, докато при стабилния метод дозировката е значително по-ниска — от 0,02 до 0,05 W/cm<sup>2</sup>.</p><h2>СПЕЦИАЛНИ ИЗИСКВАНИЯ И ПРОДЪЛЖИТЕЛНОСТ</h2><p>При провеждане на процедурите трябва да се спазват специфични правила за безопасност и ефективност. </p><ul><li><strong>Ако в зоната на третиране има наличие на метални импланти, дозировката задължително трябва да се редуцира до 1/2 или 1/3 от стандартната</strong>. </li><li><strong>При озвучаване на гръбначен стълб паравертебрално, </strong><strong>отначало се озвучава едната страна, а след това другата. Забранява </strong><strong>се преминаването напречно на гръбначния мозък. Или се изключва </strong><strong>апаратът, или пък се преминава през зоната на cauda equina</strong><strong>. </strong></li></ul><p>Продължителността на една процедура варира от 3 до 10 минути, а пълният лечебен курс обикновено включва между 10 и 15 процедури.</p><h2>ВИДОВЕ ОЗВУЧАВАНЕ И ФУНКЦИОНАЛНА ПРОВЕРКА</h2><p>Според лечебната цел и зоната на въздействие, озвучаването може да бъде:</p><ul><li><strong>Локално:</strong> За директно лечение на стави, мускули, сухожилия и рани.</li><li><strong>Рефлекторно:</strong> В зоните на Захарин-Хед за лечение на вътрешни органи.</li><li><strong>Сегментарно:</strong> Паравертебрално в областта на нервните коренчета при гръбначна патология.</li><li><strong>Ганглиотропно:</strong> Върху симпатикусови ганглии при <p>синдроми на периферни съдове, болестта на Зудек и др.</p></li><li><strong>Фонопресура (фонопунктура):</strong> Въздействие в акупунктурните точки.</li></ul><p>Изправността на ултразвуковия озвучител може да се провери лесно чрез няколко теста: </p><ul><li>Поставяне в чаша вода - причинява дегазация&nbsp;<p>и </p><p>мехурчетата въздух стават видими.</p></li><li>Накапване на вода върху мембраната - водата започва да кипи .</li><li>Поставяне на капка белтък - белтъкът загаря.</li></ul><h2>ПОКАЗАНИЯ</h2><ul><li><strong>Опорно-двигателен апарат:</strong> Артрозна болест, ревматоиден артрит, болест на Бехтерев, периартрити, бурсити, епикондилити, фрактури и контрактури (включително Дюпуитренова).</li><li><strong>Нервна система:</strong> Мононеврити, дискови хернии, невралгия на тригеминалния нерв, окципитална и интеркостална невралгия.</li><li>Гинекологични заболяваня: поствъзпалителни сраствания, салпингити, аднексити&nbsp;</li><li>Кожни заболявания: цикатрикси, келоиди</li><li>Очни заболявания: кератит, увеит, глаукома</li><li>УНГ заболявания: тонзилити, синузити</li><li><p>Стоматологични заболявания: артроза на темпоро-</p><p>мандибуларната става, невралгия на n. trigeminus,</p></li></ul><h2>Противопоказания</h2><ul><li>Възраст под 14 години поради риск от увреждане на епифизните фуги (въпреки наличието на по-нови оспорващи теории)</li><li><span class=\"editor-note\" data-note=\"**Болест на Пертес:** Представлява временно нарушение на кръвоснабдяването на тазобедрената става при деца, което води до **некроза **и деформация на главата на бедрената кост.\" id=\"note-1775061476084-0\">Болест на Пертес</span>, <span class=\"editor-note\" data-note=\"**Шойерман-Мау:** Гръбначно изкривяване (**кифоза**), причинено от клиновидна деформация на прешлените по време на интензивния растеж в юношеска възраст.\" id=\"note-1775061486975-1\">Шойерман-Мау</span>, <span class=\"editor-note\" data-note=\"**Осгуд-Шлатер:** Болезнено възпаление в горната част на пищяла под колянното капаче, което се среща често при физически активни тийнейджъри.\" id=\"note-1775061496444-2\">Осгуд-Шлатер</span>, активна туберкулоза, тумори, остри възпалителни процеси, тромбофлебит, хронична ИБС и в областите на главния и гръбначния мозък.</li><li>Бременност и директно въздействие върху матката.</li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">ФОНОФОРЕЗА</h1><h2>Същност и изисквания</h2><p>Фонофорезата представлява въвеждане на лекарствени вещества през неувредена кожа посредством ултразвук. При този процес ултразвукът действа като катализатор, който ускорява резорбцията и дифузията на лекарствата. Важно условие е <strong>лекарственото вещество да не се разрушава от ултразвука </strong>и да бъде приготвено под формата на <strong>унгвент</strong>, <strong>гел </strong>или <strong>линимент</strong>. При този метод се използват медикаменти в <strong>по-ниски дозировки</strong>, тъй като техният ефект се потенцира от действие на ултразвуковите вълни.</p><h2>Физични параметри и ефективност</h2><p>Най-голямо проникване на лекарствения препарат се постига при аплициране на ултразвук с честота <strong>880 kHz</strong>. Ефективността на проникване нараства при повишаване на интензивността от <strong>0,3 до 0,8 W/cm</strong><sup><strong>2</strong></sup>. </p><p>Изборът на методика и режим също оказва влияние върху резултатите:</p><ul><li><strong>Методика:</strong> При <strong>лабилната методика </strong>се въвежда от 20% до 40% повече вещество в сравнение със стабилната.</li><li><strong>Режим:</strong> При <strong>импулсен режим </strong>фонофоретичният ефект се намалява от 1,3 до 1,6 пъти в сравнение с <strong>непрекъснатия режим</strong>.</li></ul><h2>Практически препоръки</h2><p>За осигуряване на по-добро проникване на лекарственото вещество се препоръчва третираният участък предварително да бъде озвучен в продължение на 3–5 минути, след което да се пристъпи към самата фонофореза. След приключване на процедурата останалият върху кожата медикамент не трябва да се изтрива. Препоръчително е той да се покрие с лека превръзка, за да се гарантира неговото последействие върху организма.</p><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775043023611-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-01/text-editor-images/2026/04/1775043023611-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 511px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"><br><br></p><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Физиотерапия и рехабилитация/Материали/6-msg-Тема 6. Токове с високо напрежение и висока честота.html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">ТОКОВЕ С ВИСОКО НАПРЕЖЕНИЕ И ВИСОКА ЧЕСТОТА</h1><p>Токовете с висока честота и високо напрежение представляват електромагнитни вълни, които се разпространяват със скоростта на светлината. Основна характеристика при тях е обратнопропорционалната зависимост между дължината на вълната и честотата на тока.</p><p>Основните видове токове в тази група са:</p><ul><li><strong>Ток на Д’Арсонвал:</strong> дължина на вълната 1000-3000 m; честота 200-300 KHz.</li><li><strong>Диатермия:</strong> дължина на вълната 10-600 m; честота 1-3 MHz.</li><li><strong>УВЧ (Ултрависокочестотни токове):</strong> дължина на вълната 1-30 m; честота 10-300 MHz (стандартно 11,06 m и 27,13 MHz).</li><li><strong>Дециметрови вълни:</strong> дължина на вълната 0,1-1 m (стандартно 69 cm; честота 433 MHz).</li><li><strong>Сантиметрови вълни:</strong> дължина на вълната 1-100 cm (стандартно 12,6 cm; честота 300-30 000 MHz).</li></ul><p>В генераторите за този вид терапия се използва принципът на трептящия кръг. По време на работа <strong>енергията на електричното поле, създадена между плочите на кондензатора, се превръща в енергия на магнитното поле около проводника</strong>. </p><p>В зависимост от конкретната методика, пациентът може да бъде подложен на:</p><ol><li>Предимно електрическо поле (например УВЧ с кондензаторни електроди).</li><li>Предимно магнитно поле (обща дарсонвализация, индуктотермия, УВЧ-магнитно поле).</li><li>Цялата електромагнитна енергия (сантиметрови вълни/радар).</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">ДАРСОНВАЛИЗАЦИЯ</h2><p>Токът на Д`Арсонвал се характеризира със затихващи електромагнитни трептения. Съществуват две основни методики за приложение: обща и местна. При общата дарсонвализация пациентът се намира в специална клетка (кафез), но този метод се използва сравнително рядко в практиката.</p><h3>Физиологично действие</h3><p>При въздействие с този ток първата реакция на организма е кратък спазъм на съдовете, който веднага бива последван от <strong>мощна вазодилатация</strong>. Изключително важен ефект е разширяването на компенсаторните капиляри.</p><p>Други важни физиологични характеристики включват:</p><ul><li><strong>Невъзбудимост на нервно-мускулния апарат:</strong> Нервите и мускулите не реагират на токове с честота над 150 000 Hz.</li><li><strong>Топлинни ефекти:</strong> Поради импулсния характер на тока, образуваната ендогенна топлина не е водещ лечебен фактор.</li><li><strong>Сетивност:</strong> Пациентите усещат леко боцкане от образуването на малки точки с висока температура. Това води до <strong>снижаване на болката</strong>, <strong>тактилната и температурната сетивност</strong>, както и <strong>до значително намаляване на сърбежа</strong>.</li><li><strong>Влияние върху нервната система:</strong> Токът потиска възбудения симпатикус и има <strong>хипотензивно действие</strong>. Повлиява успешно мигренозни оплаквания, заболяване на Рейно, стенокардични пристъпи, както и разширените вени 1-2 стадий.</li><li><strong>Трофично и бактерицидно действие:</strong> Повишава неспецифичния имунитет на кожата, ускорява регенерацията и спомага за заздравяването на атонични рани.</li></ul><h3>Апликационна техника и дозировка</h3><p>Електродите за дарсонвализация имат различна форма според предназначението си и са пълни с благороден газ (аргон). При включване те светят с характерна червено-лилава светлина. Стандартният лечебен курс включва 10 до 15 процедури с времетраене от 5 до 15 минути всяка.</p><h3>Показания</h3><p>Методът се прилага успешно при:</p><ul><li>Неврози, мигрена и заболяване на Рейно.</li><li>Разширени вени (1-2 стадий).</li><li>Измръзвания и диабетни съдови нарушения.</li><li>Хемороиди, рагади, пруритус (сърбеж) и хронични екземи.</li><li>В козметичната медицина за подобряване еластицитета на кожата (лифтинг).</li><li>Кухинни процедури (вулвит, вулвовагинит) и електрокоагулация на брадавици или кожни ерозии.</li></ul><h3>Противопоказания</h3><p>Дарсонвализацията не трябва да се прилага при:</p><ul><li>Туморни формации.</li><li>Гнойни процеси.</li><li>Кръвотечения.</li><li>Наличие на пейсмейкър.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775639538839-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775639538839-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 915px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">ДИАТЕРМИЯ</h2><p>В основата на въздействието на диатермията лежат два основни физични процеса: </p><ol><li>Създаване на високочестотни колебания на частиците (йони, молекули и др.), през които преминава токът.</li><li>Генериране на мощна ендогенна топлина в резултат на тези колебания в средата на организма. </li></ol><p>Диатермията се характеризира с една от <strong>най-мощните форми на ендогенна топлина</strong>, която прегрява най-силно кожата, костите, мастната тъкан, периоста и сухожилията. По време на процедурата температурата в тъканите се повишава средно с 2 до 4ºC.</p><h3>Физиологично и терапевтично действие</h3><p>Действието на диатермичния ток е комплексно и включва следните ефекти:</p><ul><li><strong>Релаксиращ ефект:</strong> Намалява възбудимостта на двигателните нерви.</li><li><strong>Болкоуспокояващо действие:</strong> Повлиява позитивно болевата симптоматика.</li><li><strong>Бактерицидно действие:</strong> Ефективно е спрямо термолабилни бактерии, като гонококи и пневмококи.</li></ul><p>Характерно за метода е, че затоплянето продължава от 30 минути до няколко часа след края на лечебния сеанс.</p><h3>Дозировка и приложение</h3><p>Дозировката при диатермия се определя според субективните усещания на пациента и бива четири вида:</p><ol><li><strong>Атермична</strong></li><li><strong>Олиготермична</strong></li><li><strong>Термична</strong></li><li><strong>Хипертермична</strong></li></ol><p>Освен в терапевтичната практика, диатермията намира приложение и в хирургията под формата на диатермичен нож, като там се използват термични и хипертермични дозировки.</p><h3>Показания и ограничения</h3><p><strong>Поради мощната ендогенна топлина и реалната опасност от прегряване на тъканите, този метод се прилага само при определена патология</strong>. Основните показания включват заболявания на малкия таз, като:</p><ul><li>Аднексити</li><li>Салпингити</li><li>Салпингоофорити</li><li>Простатити</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">УЛТРАВИСОКОЧЕСТОТНИ ТОКОВЕ (УВЧ)</h2><p>Принципът на въздействие при УВЧ терапията се основава на възникването на резонанс, когато терапевтичната и техническата верига на апарата започнат да трептят с еднаква честота. Основният лечебен фактор при тези токове е образуването на <strong>ендогенна топлина</strong>.</p><h3>Видове електроди и технически особености</h3><p>За излъчване на ултрависокочестотната енергия се използват няколко специфични вида електроди:</p><ul><li><strong>Кондензаторни електроди </strong>(електроди на Шлифаке).</li><li><strong>Индукционни електроди&nbsp;</strong>(електроди на Коваршик).</li><li><strong>Минод и монод:</strong> това са електродите на Петцолд и Кебел, които осигуряват по-дълбоко въздействие на магнитното поле и по-равномерно разпределение на топлината, доближавайки се до ефекта на микровълните (сантиметровите вълни).</li></ul><p>УВЧ токовете се характеризират с това, че не предизвикват електролиза или поляризационни явления в тъканите. Благодарение на ниското съпротивление, тяхното проникване в дълбочина е лесно и в голям обем.</p><h3>Характеристики на ендогенната топлина</h3><p>Ендогенната топлина, генерирана от УВЧ, се различава съществено от екзогенните източници (като парафина) по следните белези:</p><ul><li>Притежава значително по-голяма прониквателна способност.</li><li>Не задейства терморегулаторните механизми на тялото.</li><li>Не обременява дейността на сърдечната, дихателната и отделителната системи.</li><li>Продължава да се образува в тъканите дори след като излъчването е преустановено.</li><li>Излъчването ѝ от организма обратно в средата става много по-бавно.</li></ul><p>Тази топлина предизвиква мощен вазодилатативен ефект, който е специфичен с това, че не се повлиява от действието на симпатикомиметици като адреналин.</p><h3>Физиологично и терапевтично действие</h3><p>Въздействието на УВЧ зависи силно от приложената доза: малките атермични и олиготермични дози активират жизнените процеси, докато интензивните дози имат потискащо действие.</p><ul><li><p><strong>Сърдечно-съдова система:</strong> При хипертонична болест І-ІІ степен има <strong>хипотензивно </strong>действие, особено при третиране на рефлексогенни зони като синус каротикус, надбъбречна област и плексус соларис</p><p>. Има <strong>антиспатично</strong> действие при периферни съдови смущения като болест на Рейно и акроцианоза</p><p>.</p></li><li><p><strong>Нервна система:</strong> Малките атермични дози стимулират способността на нерва да се регенерира и повишават неговата възбудимост. УВЧ има силен <strong>обезболяващ </strong>ефект при невралгии, неврити и миалгии. Имат </p><p>мощен <strong>противовъзпалителен ефект</strong>, който може да се приложи </p><p>при менингити, енцефалити, полиомиелити и др.</p> Върху вегетативната нервна система предизвиква <strong>симпатиколиза</strong>. </li><li><p><strong>Ендокринна система:</strong> Стимулира надбъбреците (отделяне на кортикостероиди) и хипофизата, което е полезно при ревматизъм, дисменорея и безвкусен диабет.</p><br></li><li><p><strong>Дихателна система:</strong> Противовъзпалително и спазмолитично действие при хронифицирани пневмонии, трахеобронхити и абсцеси.</p><br></li><li><p><strong>Отделителна система:</strong> Оказва обезболяващ и диуретичен ефект при бъбречни кризи, анурии, нефропатии и отравяния с живак или сулфонамиди.</p><br></li><li><p><strong>Храносмилателна система:</strong> Спазмолитично, обезболяващо и трофично действие.</p><br></li><li><strong>Травматология и хирургия:</strong> Изключително ефективна при <strong>измръзвания</strong>, тъй като ендогенната топлина не уврежда тъканите допълнително. Използва се при <p><strong>посттравматични </strong>и <strong>постоперативни </strong></p><p><strong>заболявания</strong>, за лечение на </p>артропатии, контузии, хематоми и в <strong>гнойната хирургия </strong>за лечение на остеомиелити, мастити, фурункули и карбункули</li></ul><h3>Методика на приложение и дозировка</h3><p>Дозировката се определя както във ватове според монитора, така и според субективното усещане на пациента: атермична, олиготермична, термична и хипертермична. Хипертермичните дози се ползват по-рядко (при миозити, астма, болест на Бехтерев).</p><p>Курсът обикновено включва 10–15 процедури с времетраене от 5 до 15 минути. </p><p>При определяне на разстоянието между електродите и тялото трябва да се знае:</p><ul><li><strong>Минимално разстояние:</strong> води до по-повърхностно затопляне.</li><li><strong>По-голямо разстояние (<u>до 6 см</u>):</strong> разсейва енергията и намалява поглъщането.</li><li><strong>Напречно разположение (от двете страни):</strong> за въздействие в дълбочина.</li><li><strong>Надлъжно разположение (в една линия):</strong> за повърхностно въздействие.</li></ul><h3>Противопоказания</h3><ul><li>Туморни формации.</li><li>Пейсмейкър. </li><li>Метални импланти.</li><li>Кръвотечения. </li></ul><p>По време на курса трябва да се следи за възможни хипотензивни реакции.</p><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775640213347-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775640213347-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 1055px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">СВРЪХВИСОКОЧЕСТОТНА ТЕРАПИЯ<br>ДЕЦИМЕТРОВИ ВЪЛНИ</h2><p>Източници на дециметрови вълни (ДМВ) са генератори за свръхвисока честота (СВЧ), които са конструирани на <strong>магнетронен принцип</strong>. Тези апарати са снабдени с няколко вида лъчители: с кръгло поле, с продълговато поле и седловиден лъчител. Изборът на лъчител зависи от патологичния процес, като кръглият се използва при повърхностни процеси като абсцеси и фурункули, надлъжният (линеарен) при неврити и тромбофлебити, а седловидният е предназначен за тазобедрени и други дълбоки стави. Процедурите се извършват от дистанция между 3 и 10 см.</p><h3>Дозиране и методика на приложение</h3><p>Дозирането на дециметровите вълни се извършва чрез <strong>отчитане на ватовете на монитор</strong><strong>а</strong> и според <strong>субективните усещания на пациента</strong>: атермична, олиготермична, термична и хипертермична. </p><p>При наличие на остри процеси се препоръчва използването на атермични и олиготермични дозировки. Когато въздействието е насочено директно върху нервните сплитове, задължително се прилагат атермични дозировки.</p><h3>Биологично и терапевтично действие</h3><p>Физическите свойства на ДМВ се приближават максимално до качествата на светлината. Колкото по-отдалечен е лъчителят от тялото, толкова по-голямо е разсейването на полето и по-нисък неговият интензитет. Явленията на рефлектиране при дециметровите вълни са значително по-малки в сравнение с микровълните и достигат максимум 20–30%. Поради това не се наблюдават характерните за микровълните „hot spots“ и се възпрепятства образуването на „стоящи вълни“, което води до минимално термично обременяване на мастната тъкан.</p><p>ДМВ имат голяма <strong>прониквателна способност</strong>, достигаща от <strong>9 до 12 см</strong> в дълбочина. Те стимулират образуването на антитела и активират неспецифичните фактори на имунната защита. Основният терапевтичен ефект е свързан с генерирането на мощна <strong>ендогенна топлина</strong>, която не прегрява тъканите поради своето равномерно разпределение.</p><h3>Индикации за лечение</h3><p>Дециметровите вълни се препоръчват в случаите, когато е необходимо хомогенно и дълбоко загряване, постигане на трайна хиперемия и разнасяне на патологични инфилтрати. Най-честите индикации включват:</p><ul><li>Заболявания на опорно-двигателния апарат: <strong>артрози</strong>, <strong>спондилатрози</strong>, <strong>болест </strong>на <strong>Бехтерев </strong>и <strong>остеомиелити</strong>.</li><li>Неврологични заболявания: <strong>невралгии</strong>, <strong>дископатии </strong>и <strong>дискови хернии</strong>.</li><li>Възпалителни процеси: <strong>мастити</strong>, <strong>аднексити</strong>, <strong>простатити </strong>и <strong>тромбофлебит</strong>.</li><li>Заболявания на дихателната система: <strong>бронхопневмонии </strong>и <strong>бронхиална астма</strong>.</li></ul><p>Специфични клинични проучвания доказват ефективността на ДМВ при конкретни патологии:</p><ul><li><strong>Ревматоиден артрит:</strong> Отбелязва се много добро повлияване при дозировка 40–50 W в зоната от Th10 до L4.</li><li><strong>Захарен диабет:</strong> Облъчването в проекцията на панкреаса с мощност 30 W води до понижаване на кръвната захар.</li><li><strong>Хроничен пиелонефрит:</strong> Дозировки от 20–40 W имат противовъзпалително действие, намаляват болката и понижават кръвното налягане.</li></ul><h3>Противопоказания</h3><p>Приложението на дециметрови вълни е противопоказано при следните състояния:</p><ul><li>Туморни разраствания и смущения в кръвоснабдяването.</li><li>Смущения в температурната сетивност.</li><li>Наличие на пейсмейкър или метална остеосинтеза в зоната на въздействие.</li><li>Областта на епифизарните части на костите при деца.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">САНТИМЕТРОВИ ВЪЛНИ (МИКРОВЪЛНОВА ТЕРАПИЯ – РАДАР)</h2><p>Сантиметровите вълни (СМВ) заемат междинно място между инфрачервените лъчи и ултрависокочестотните (УВЧ) вълни. Законите за тяхното разпространение, отражение и поглъщане се приближават до тези на светлината. При преминаване през тела с различна плътност се наблюдава значително отразяване и поглъщане, като вълнените платове поглъщат енергията особено силно. Поради високия коефициент на разсейване, вълните се насочват към зоната на въздействие чрез специални излъчватели с форма на полусфера или полуцилиндър.</p><p>Съгласно държавните стандарти, апаратите за микровълнова терапия се стационират в т. нар. <strong>Фарадееви клетки</strong>, за да се избегнат смущения в радио и телевизионните предавания.</p><h3>Апаратура и методика на приложение</h3><p>Генераторната лампа на апаратите представлява многорезонаторен магнетрон, а излъчваната енергия се измерва във ватове. При провеждане на процедурата излъчвателят се насочва от разстояние 5 до 10 см, като е задължително участъкът за въздействие да бъде открит. Преди започване трябва да се отстранят всякакви метални части и предмети от зоната на облъчване, като се обръща специално внимание на наличието на импланти. Изключително важно е да не се подлагат на облъчване органи със слабо развита кръвоносна система, като очи, тестиси и яйчници.</p><h3>Дозировка и времетраене</h3><p>Дозировките се определят на базата на ватовете, отчетени на монитора, и субективното усещане на пациента:</p><ul><li><strong>Атермична:</strong> до 10 W.</li><li><strong>Олиготермична:</strong> от 15 до 30 W.</li><li><strong>Термична:</strong> от 30 до 60 W.</li><li><strong>Хипертермична:</strong> над 70 W.</li></ul><p>Стандартният лечебен курс включва между 10 и 15 процедури, като времетраенето на всяка сесия варира от 5 до 15 минути.</p><h3>Механизъм на действие и терапевтичен ефект</h3><p>Тъканите в човешкото тяло поглъщат между 40% и 100% от микровълновата енергия, което ограничава проникването ѝ до дълбочина от 5–6 см. <strong>Тъканите, богати на вода и течна среда (кръв, лимфа, мускули, черен дроб, бъбреци), поглъщат микровълните в най-голяма степен</strong>. Тъкани с по-голяма плътност и ниско съдържание на течности (сухожилия, кости, подкожна тъкан) имат много по-слаба абсорбция. </p><p>Микровълните създават мощна и правилно разпределена ендогенна топлина, като при тях електричната съставка преобладава над магнитната. Освен температурните промени, терапията предизвиква съдово-вегетативни реакции, включително намаляване на патологично повишения съдов пермеабилитет. Този ефект се дължи на снижаването на нивата на серотонин и хепарин в кожата, което осигурява допълнително противовъзпалително и антиалергично действие.</p><h3>Показания за лечение</h3><p>Микровълновата терапия е показана при широк спектър от заболявания:</p><ul><li><strong>Заболявания на опорно-двигателния апарат:</strong> миозити, тендовагинити, бурсити, периартрити, инсерционити и артрозна болест (коксартроза, гонартроза и др.).</li><li><strong>Неврологични заболявания:</strong> неврити, плексити, дископатии и спондилози с радикулерен синдром.</li><li><strong>Вътрешни заболявания:</strong> пневмонии, плеврити, цистити, простатити и параметрити.</li><li><strong>УНГ заболявания:</strong> отити и синуити, като най-добър ефект се постига чрез контактен радар.</li><li><strong>Гнойна хирургия:</strong> фурункули, карбункули, мастити, абсцеси, хидросаденити и панарициуми.</li></ul><h3>Специални предупреждения и противопоказания</h3><p>При лечение трябва да се имат предвид възможните <strong>хипотонични реакции</strong>, произтичащи от ефекта на вълните върху барорецепторите, дори при третиране на отдалечени зони като колянната става. </p><blockquote><strong>КРИТИЧНО ВАЖНО Е ДА НЕ СЕ ИЗВЪРШВАТ ПРОЦЕДУРИ В СЪРДЕЧНАТА ОБЛАСТ, ТЪЙ КАТО МИКРОВЪЛНИТЕ ПРЕДИЗВИКВАТ СПАЗЪМ НА КОРОНАРНИТЕ АРТЕРИИ</strong>.</blockquote><p><strong>Противопоказания:</strong></p><ul><li>Туморни процеси и кръвни заболявания.</li><li>Наличие на пейсмейкър или метални импланти.</li><li>Болест на Бюргер.</li><li>Въздействие върху епифизите при деца.</li></ul><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>","files/Физиотерапия и рехабилитация/Материали/7-msg-Тема 7. Фототерапия и Лазертерапия..html":"<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">ФОТОТЕРАПИЯ</h1><h2>Определение и физична характеристика</h2><p>Фототерапията е приложението на инфрачервените (ИЧЛ), видимите (BЛ) и ултравиолетовите лъчи (УВЛ) от светлинния спектър за лечебни и профилактични цели. </p><p>Светлината се причислява към квантовите излъчвания, които представляват потоци от елементарни частички, носители на определено количество енергия. Тя се разпространява вълнообразно и в спектъра на лъченията заема междинно място между микровълните и рентгеновите лъчи.</p><h2>Видове светлинни лъчи</h2><p>Светлинните лъчи се разделят според дължината на вълната на следните групи:</p><ul><li><strong>Инфрачервени:</strong> 10 000 nm – 760 nm</li><li><strong>Видими:</strong> 760 nm – 400 nm</li><li><strong>Ултравиолетови:</strong> 380 nm – 10 nm</li><ul><li>Група А (380 nm – 320 nm) – луминесцентни</li><li>Група B (320 nm – 275 nm) – еритемни</li><li>Група C (&lt; 270 nm) – бактерицидни</li></ul></ul><h2>Източници на светлина</h2><p>Източниците биват <strong>естествени </strong>(слънчево лъчение) и <strong>изкуствени</strong>:</p><ul><li><strong>За видими и инфрачервени лъчи (топлинни):</strong> солукс, инфраруж.</li><li><strong>За ултравиолетови лъчи (луминесцентни):</strong> аргоно-живачно-кварцови лампи (стационарни и портативни), фотарийни (за помещения и групово облъчване) и бактерицидни.</li><li><strong>За лазерно лъчение.</strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">Инфрачервени лъчи (ИЧЛ)</h2><p>ИЧЛ са топлинни лъчи, които проникват на около <strong>5 см под кожата</strong>, където <strong>енергията им се трансформира в топлинна</strong>. При тяхното действие се наблюдава топлинен еритем (<strong>!!erythema calorica!!</strong>), който има следните характеристики:</p><ul><li>Неравномерен и петнист характер.</li><li>Без ясно очертани граници.</li><li>Появява се след няколко минути.</li><li>Изчезва до половин-един час след спиране на въздействието.</li></ul><h3>Основно действие на ИЧЛ</h3><ul><li>Обезболяващо и противовъзпалително действие.</li><li>Антиспастично действие.</li><li>Стимулиране на трофиката на тъканите и регенерацията на кожата и периферните нерви.</li></ul><h2>Показания за приложение на ИЧЛ</h2><ul><li><strong>Заболявания на периферната нервна система:</strong> неврити, невралгии, радикулити, полиневропатии, дискова херния, парализи и мускулни атрофии.</li><li><strong>Катари на горни дихателни пътища.</strong></li><li><strong>Заболявания на опорно-двигателния апарат:</strong> артрозна болест, миалгии, миозити, тендовагинити, бурсити, състояния след фрактури, дисторзио и др.</li><li><strong>Възпалителни заболявания на гениталиите.</strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">Видими лъчи (ВЛ) и Хромотерапия</h2><p>В спектъра на видимите лъчи се различават 7 цвята: червен, оранжев, жълт, зелен, небесносин, тъмносин и виолетов. Те се възприемат чрез рецептори в ретината, чието възбуждане активира нервни вериги в мозъка, включително връзки с хипоталамусните центрове за регулация на ендокринните функции.</p><p>Различават се два основни биологични ефекта на ВЛ:</p><ol><li><strong>Визуално:</strong> зрителна химична реакция, водеща до освобождаване на хормони.</li><li><strong>Чрез кожата:</strong> основано на електромагнитно въздействие.</li></ol><p>Топлинното действие и прониквателната способност на ВЛ отстъпват пред тези на ИЧЛ. Основното им въздействие е върху <strong>психическото състояние </strong>(настроение, трудоспособност, сън и апетит) чрез зрителния анализатор. Този тип лечение се нарича <strong>Хромотерапия</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">Ултравиолетови лъчи (УВЛ)</h2><h3>Физиологични и биологично действие</h3><p>Ултравиолетовите лъчи проникват на около <strong>0,5 мм под кожата, където светлинната енергия се трансформира в химична</strong>. Този процес отключва редица биохимични реакции с широк спектър на въздействие върху организма:</p><ul><li><p>!Нормализиране на артериалното налягане!.</p></li><li><p>Стимулиране имунобиологичната активност.</p></li><li><p>З</p><p>асилване регенеративните способности на кожата и периферните нерви.</p></li><li><p>Подтискане алергичните реакции.</p></li><li><p>В еритемни дози подтискат възбудимостта на сетивните нерви (обезболяващо действие).</p></li><li><p>Бактерицидно действие (254– 260 nm) – денатурация на белтъците и структурни промени </p><p>в ДНК.</p></li><li><p>Влияние върху обмяната на веществата (калциево-фосфорен обмен, образуване на витамин </p><p>D, нормализира въглехидратната и белтъчната обмяна) (265– 280 nm).</p></li><li><p>Стимулиране функциите на ендокринните жлези.</p></li><li><p>Стимулиране на еритропоезата.</p></li></ul><h3>Ултравиолетов еритем (<u>erythema photoelectrica</u>) </h3><p>При облъчване с УВЛ се формира специфична реакция, известна като <strong>ултравиолетов еритем</strong>, която се отличава със следните характеристики:</p><ul><li>Има хомогенен характер и ясно очертани граници.</li><li>Появява се след латентен период от 2, 4, 6 до 12 часа.</li><li>Еритемът не изчезва веднага, а преминава в пигментация вследствие на образувания меланин в базалния слой на епидермиса.</li></ul><h3>Фактори на индивидуалната чувствителност</h3><p>Чувствителността към УВЛ не е еднаква при всички хора и зависи от редица вътрешни и външни фактори:</p><ul><li><strong>Биологични особености:</strong> Хората със светла, влажна и добре кръвоснабдена кожа са по-чувствителни. Мъжете проявяват по-голяма чувствителност от жените, а възрастовият пик на чувствителност е между 20 и 50 години.</li><li><strong>Външна среда:</strong> Престоят на голяма надморска височина повишава чувствителността.</li><li><strong>Медикаменти и храна:</strong> Приемането на определени фотосенсибилизатори като риванол, йод, олово, живак, пеницилини и сулфонамиди значително повишава реактивността към лъчите.</li><li><strong>Заболявания:</strong>&nbsp;</li><ul><li>Чувствителността се повишава при хиперфункция на щитовидната жлеза, пневмонии, артрити, колагенози и интоксикации.&nbsp;</li><li>Тя намалява при неврологични заболявания, инфекциозни процеси, анемия, кахексия и микседем.</li></ul></ul><h3>Регионална чувствителност</h3><p>Различните части на тялото реагират с различна интензивност на една и съща доза УВЛ:</p><ul><li><strong>100%:</strong> Корем, гръб и лумбална област.</li><li><strong>75%:</strong> Гърди и лице.</li><li><strong>50%:</strong> Сгъвни и разгъвни повърхности на крайниците.</li><li><strong>25%:</strong> Длани и ходила.</li></ul><h3>Показания за УВЛ облъчване (УВО)</h3><p>УВО се прилага по различни методики в зависимост от търсения ефект:</p><ul><li><strong>Местно облъчване:</strong> Използва се при бронхити, пневмонии, бронхиална астма, гинекологични заболявания, рани, забавено калусообразуване и увреди на периферните нерви.</li><li><strong>Рефлекторно въздействие (еритемна яка и гащета):</strong> Цели блокиране на симпатикуса и се прилага при нощно напикаване (enuresis nocturna), стерилитет, гинекологични проблеми и заболявания на периферните съдове.</li><li><strong>Локално чрез тубус:</strong> Прилага се в носа и устата при синуити, тонзилити, фарингити и ринити.</li></ul><h3>Противопоказания</h3><p>Облъчването с УВЛ е противопоказано при следните състояния:</p><ul><li>Хиперфункция на щитовидната жлеза и надбъбреците.</li><li>Активна туберкулоза и туморни процеси.</li><li>Склонност към хеморагии и фебрилитет.</li><li>Остри инфекциозни състояния и колагенози.</li></ul><h3>Дозиране и биодоза </h3><p>Дозирането при светлолечението се определя от разстоянието на източника до тялото и времетраенето. При УВЛ дозирането е строго индивидуално и става чрез определяне на биодоза с биодозиметъра на Далфелд-Горбачов.</p><ul><li>Една биодоза е <strong><p>времето, за което се получава минимална еритема, </p><p>но с ясно очертани граници, при разстояние между горелката и телесната </p><p>повърхност 50 cm</p></strong>.</li><li>Резултатът се отчита след 12 или най-късно след 24 часа от облъчването и се измерва в <strong>минути/секунди</strong>.</li><li><p>Определянето на биодозата позволява прецизиране на </p><p>дозировката в рамките на суберитемната доза — 1/8, 1/4, 1/2 от биодозата, или </p><p>еритемната доза съдържаща от 1 до 5 биодози.</p><br></li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775642279632-image.png\" alt=\"image\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775642279632-image.png\" data-width=\"100\" data-align=\"center\" style=\"width: 320px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">ЛАМПА СОЛУКС</h2><p>Лампата солукс е източник на <strong>инфрачервени </strong>(ИЧЛ) и <strong>видими лъчи </strong>(ВЛ). Физиологичното ѝ действие е предимно топлинно, като предизвиква образуването на <strong>топлинен еритем</strong> (erythema calorica) в облъчваните зони.</p><h3>Техника на приложение и филтри</h3><p>При провеждане на процедурата лампата се поставя <strong>косо </strong>на разстояние 70-100 см от мястото на въздействие. Косото разположение има за цел да намали риска от нараняване на пациента или персонала при евентуална авария. Апаратът може да работи с различни филтри, които променят диапазона на пропусканите лъчи:</p><ul><li><strong>Червен филтър:</strong> Пропуска предимно червената част на видимите лъчи и късовълновите инфрачервени лъчи. Тези лъчи оказват физиологично въздействие на по-голяма дълбочина в тъканите.</li><li><strong>Син филтър:</strong> Пропуска синята част от видимите лъчи и съвсем малко количество инфрачервени лъчи. Лъчистата енергия прониква на малка дълбочина, поради което действието е нежно, повърхностно топлинно и противовъзпалително.</li></ul><h3>Дозировка и времетраене</h3><p>Процедурите се провеждат ежедневно, като е възможно да се прилагат и два пъти дневно. Продължителността на една сесия варира от 10 до 30 минути. Пълният курс на лечение обикновено включва между 10 и 20 процедури.</p><h3>Показания</h3><ul><li>Синуити, ринити и фарингити.</li><li>Пареза на n. facialis и невралгия на n. trigeminalis.</li><li>Плексити, радикулити и миалгии.</li><li>Цистити и други възпалителни състояния.</li></ul><h3>Противопоказания</h3><ul><li>Наличие на тумори.</li><li>Кръвотечения.</li><li>Активна туберкулоза.</li><li>Фебрилни състояния.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">ЛАМПА ИНФРАРУЖ</h2><p>Лампата инфраруж е топлинен източник на лъчиста енергия, в чийто спектър преобладават предимно червените и инфрачервените лъчи. </p><h3>Физиологично действие и ефективност</h3><p>Основното действие на лампата е топлинно. Топлината прониква дълбоко в тъканите, където:</p><ul><li>Създава хиперемия и разширява кръвоносните съдове.</li><li>Отстранява спазмите на гладката и напречно набраздената мускулатура.</li></ul><p><strong>Топлинният еритем </strong>при инфраруж е с <strong>много по-голям интензитет в сравнение с този на солукса</strong>. Това прави лечебния ефект по-силен при заболявания на по-дълбоко разположени органи и тъкани.</p><h3>Методика на провеждане</h3><p>За разлика от солукса, тази лампа се поставя <strong>перпендикулярно </strong>на третираната зона на разстояние 70-100 см. Препоръчително е лицето и останалите части на тялото, които не се третират, да бъдат покрити с чаршаф. Процедурите са ежедневни (еднократно или двукратно) с времетраене 10-15 минути. Лечебният курс се състои от 10 до 20 процедури.</p><h3>Показания</h3><ul><li>Плексити, радикулити и миалгии.</li><li>Хроничен хепатит и холецистит.</li><li>Нефролитиаза и цистит.</li><li>Хронични гинекологични възпаления и различни травми.</li></ul><h3>Противопоказания</h3><p>Противопоказанията са същите като при лампа солукс: </p><ul><li><p>Наличие на тумори.</p></li><li><p>Кръвотечения.</p></li><li><p>Активна туберкулоза.</p></li><li><p>Фебрилни състояния.</p></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">АРГОНО-ЖИВАЧНО-КВАРЦОВА ЛАМПА</h2><h3>Обща характеристика</h3><p>Аргоно-живачно-кварцовите лампи се разделят на стационарни и портативни според своята мобилност. Те излъчват ултравиолетови лъчи (УВЛ) с дължина на вълната от 380 до 180 nm, като най-висок е интензитетът на УВ-В лъчите. В процеса на работа се генерират и минимални количества видими и инфрачервени лъчи вследствие на нагряването на електродите, поради което при процедури от близко разстояние пациентът усеща лека топлина.</p><h3>Работа с кварцовата лампа</h3><p>При провеждане на процедурата е необходимо да се спазват следните правила:</p><ul><li>Пациентът заема удобно положение (на стол или кушетка).</li><li>Задължително е поставянето на тъмни очила на пациента и персонала за защита на зрението от преките УВЛ.</li><li>Полето около третираната зона се изолира с бели кърпи или чаршафи.</li><li>Лампата се насочва така, че лъчите да падат перпендикулярно върху кожата.</li><li>Времетраенето се определя индивидуално според предварително снетата биодоза.</li></ul><h3>Общо ултравиолетово облъчване</h3><p>Общото облъчване се прилага в суберитемни дози (от 1/4 до 2 биодози). При деца и пациенти с повишена чувствителност се започва с по-ниски нива — 1/6 или 1/8 от биодозата. Дозировката се увеличава постепенно с 1/4 биодоза на всеки 1 или 2 дни, като курсът обикновено включва 20—25 процедури.</p><p>Този метод се прилага за:</p><ul><li>Профилактика и лечение на рахит и остеопороза.</li><li>Закаляване на организма.</li><li>Лечение на катари на горните дихателни пътища и при грипни епидемии.</li><li>Костно-ставна, кожна и неактивна белодробна туберкулоза.</li></ul><h3>Местно ултравиолетово облъчване</h3><p>Местното облъчване се извършва предимно с еритемни дози, вариращи от 1 до 5 и повече биодози. Поради различната регионална чувствителност на кожата е необходимо биодозата да се определя отделно за всяко поле, подлежащо на третиране. </p><p>Размерите на еритемните полета са между 100 и 600 cm<sup>2</sup>. В рамките на един ден могат да се облъчват до две полета, при условие че общата им площ не надвишава 800 cm<sup>2</sup>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">ФОТАРИАЛНИ ЛАМПИ</h2><p>Фотариалните лампи се използват за масови профилактични облъчвания с ултравиолетови лъчи (УВЛ) на <strong>колективи </strong>в предприятия, училища, детски градини и други организации. Най-често те се поставят в специално пригодени помещения, наречени фотариуми.</p><p>Основни характеристики на фотариума:</p><ul><li>Лампата се разполага в центъра на помещение с площ от 24 до 40 m<sup>2</sup>.</li><li>Помещението трябва да бъде светло, с добро отопление и под, постлан с паркет.</li><li>Работното място на медицинския персонал е отделено от фотариума чрез прозорче за наблюдение и даване на указания.</li></ul><p>Тези лампи се използват основно за <strong>закаляване </strong>и за <strong>масова профилактика срещу грипни и простудни заболявания </strong>на горните дихателни пътища.<img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775642300693-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775642300693-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-04-08/text-editor-images/2026/04/1775642300693-image.png\" data-width=\"60\" data-align=\"center\" style=\"width: 382.2px; max-width: 100%; height: auto; display: block; float: none; margin: 8px auto\" data-broken-cleanup-bound=\"1\"></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">БАКТЕРИЦИДНИ ЛАМПИ</h2><p>Бактерицидните лампи са източник на УВЛ от група С с дължина на вълната от 275 до 180 nm. Техният ефект се основава на фотохимичното действие на лъчите върху протоплазмата и ензимите на бактериите и вирусите.</p><p>Приложение:</p><ul><li>Дезинфекция на въздух, вода и повърхности.</li><li>Обработка на операционни и родилни зали, детски стаи, микробиологични лаборатории и промишлени цехове със замърсена среда.</li></ul><p>Важно е да се отбележи, че това облъчване е само допълнение към санитарно-противоепидемичните мероприятия като краен етап от обработката. Директното облъчване на живи организми с УВ-С лъчи е опасно, тъй като предизвиква поражения върху кожата и очите.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2 style=\"text-align: center\">АНТАГОНИЗЪМ И СИНЕРГИЗЪМ ПРИ СВЕТЛОЛЕЧЕНИЕТО</h2><p>Взаимодействието между различните видове светлинни лъчи може да доведе до засилване или отслабване на биологичния ефект:</p><ul><li><strong>Синергично действие:</strong> Наблюдава се при едновременно облъчване с трите вида лъчи (ИЧЛ, ВЛ и УВЛ) или при предварително облъчване с видими и инфрачервени лъчи. В тези случаи еритемната реакция се усилва поради сумиране на ефектите.</li><li><strong>Антагонизъм:</strong> Проявява се, ако инфрачервените и видимите лъчи се приложат по време на латентния период на ултравиолетовия еритем. Това води до отслабване на еритемната реакция.</li></ul><p>Причината за антагонизма е предварително интензифицираната обмяна на веществата и усилената микроциркулация. Това води до по-бързо изнасяне на междинните продукти още в латентния стадий, което намалява крайната сила на еритемната реакция.</p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">ЛАЗЕРТЕРАПИЯ</h1><h2>Определение и същност</h2><p>Лазертерапията се дефинира като усилване на светлината чрез стимулирана емисия на радиация (Light Amplification by Stimulated Emission of Radiation). Първият квантов оптичен генератор, известен като лазер (LASER), е създаден през 1960 г.. В широк смисъл светлината представлява електромагнитни вълни с различна честота, а в по-ограничен аспект тя е видимо излъчване, което предизвиква зрително усещане. Това явление има две страни: субективно-физиологична за облъчения индивид и обективно-физична, свързана с източника и средата на разпространение.</p><h2>Устройство на лазера</h2><p>Устройството на лазера включва няколко основни компонента: </p><ul><li><strong>Активна лазерна среда</strong> (работно вещество или медиум).</li><li><strong>Източник на енергия </strong>(електрически ток) за стимулиране и възбуждане на активната среда.</li><li><strong>Система от огледала</strong> (резонаторно и рефлектиращо)&nbsp;</li><li><strong>Световод</strong>, който отвежда лазерния сноп до наконечника.&nbsp;</li></ul><p>Генераторите се класифицират според агрегатното състояние на работната среда на:</p><ul><li><strong>Твърди:</strong> рубинови и полупроводникови.</li><li><strong>Течни:</strong> разтвори от органични багрила.</li><li><strong>Газови:</strong> хелий-неонов, аргон-криптонов и въгледвуокисов.</li></ul><h2>Принцип на действие и режими</h2><p>Стимулираната емисия възниква, когато под въздействие на погълната енергия от фотон, електронът прескача на по-ниско енергетично ниво, което е придружено с излъчване на нов фотон, идентичен по енергия с първоначалния. Усилването на светлината се постига чрез положителна обратна връзка, при която част от усиленото излъчване се връща обратно на входа за последващо усилване. </p><p>Лазерите работят в два основни режима:</p><ul><li><strong>Постоянен (непрекъснат) режим:</strong> Потокът на мощността се измерва във ватове на единица площ (<strong>W/cm<sup>2</sup></strong>).</li><li><strong>Импулсен режим:</strong> Интензитетът на лъчението се измерва чрез плътността на енергията върху единица площ, изразена в джаули (<strong>J/cm<sup>2</sup></strong>).</li></ul><p>Според изходната мощност лазерите биват <strong>нискоенергийни </strong>и <strong>високоенергийни </strong>(<strong>с мощност над 0,5W</strong>). При нискоенергийните модели дълбочината на проникване е само няколко милиметра поради пречупване, отражение и разсейване на лъчите на границата между оптично разнородните тъкани.</p><h2>Характеристики на лазерното лъчение</h2><p>Лазерното лъчение представлява електромагнитни вълни в светлинния диапазон със следните специфични свойства:</p><ul><li><strong>Монохроматичност:</strong> излъчване само с една дължина на вълната.</li><li><strong>Кохерентност:</strong> всички вълни се разпространяват в една и съща фаза.</li><li><strong>Насоченост:</strong> изключително малка дивергенция на лъчите.</li></ul><h2>Терапевтични ефекти</h2><ul><li>Противовъзпалителен.</li><li>Обезболяващ.</li><li>Регенеративен.</li><li>Съдоразширяващ.</li><li>Стимулиращ имунната защита.</li><li>Десенсибилизиращ.</li><li>Противомикробен.</li></ul><h2>Показания за лазертерапия</h2><p>Методът е показан при широк кръг от заболявания:</p><ul><li><strong>Заболявания на опорно-двигателния апарат:</strong> дегенеративни, възпалителни, травматични и професионални заболявания като артрози, артрити, периартрити, тендовагинити, епикондилити, дисторзии, контузии и състояния след фрактури.</li><li><strong>Заболявания на нервната система:</strong> плексити, радикулити, дископатии, неврити, херпес зостер и травматични лезии на периферни нерви.</li><li><strong>Кожни заболявания:</strong> уртикария, невродермит, сърбящи дерматози, херпес симплекс, бавно зарастващи язви, рани (включително следоперативни) и декубитуси.</li></ul><h2>Противопоказания</h2><p>Лазертерапията не трябва да се прилага в следните случаи:</p><ul><li>В областта около очите и в проекцията на растящи епифизи.</li><li>Наличие на тумори, бременност и хеморагии.</li><li>Инфекциозни болести и тиреотоксикоза.</li><li>Сърдечносъдова и белодробна недостатъчност (II-III степен) и декомпенсиран захарен диабет.</li></ul><h2>Изисквания за безопасност</h2><p>При работа с лазер е необходимо стриктно спазване на мерки за безопасност:</p><ul><li>Лазерът трябва да се монтира в отделно помещение или изолирана кабина, като на вратата се поставя <span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fcdn11.bigcommerce.com%2Fs-11317%2Fimages%2Fstencil%2F1280x1280%2Fproducts%2F689%2F3640%2FW24H__97610.1265111764.jpg%3Fc%3D2&amp;f=1&amp;nofb=1&amp;ipt=f6c9d78799e964ebf74894151868de46fb81abb00f38cb4db5e1959dd734af3c &quot;width=60%&quot;)\" id=\"note-1775061969366-0\">забранителен знак</span> за влизане по време на процедура.</li><li>При използване на хелий-неонов лазер (червена светлина) се изискват сини защитни очила за персонала и пациента, както и сини стени, завеси и облекло.</li><li>Лазерният лъч никога не трябва да се насочва директно към очите.</li><li>В кабинета не трябва да има отразяващи предмети или лични вещи (часовници, гривни, пръстени), които могат да предизвикат рефлексия.</li></ul><br><br><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1200px; </p><p>      margin: 2rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.6; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1 { </p><p>      font-weight: 600; </p><p>      font-size: 1.5em;</p><p>      margin-top: 1.5em;</p><p>      margin-bottom: 0.5em;</p><p>      color: #3a5a40;</p><p>      border-bottom: 2px dashed #a3b18a;</p><p>      padding-bottom: 5px;</p><p>    }</p><p>    p { </p><p>      margin: 0.7em 0 1.5em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body { font-size: 16px; }</p><p>      h1 { font-size: 1.3em; }</p><p>    }</p><p>  </style>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>"};
